// models
export interface ICorLinkPreview {
  url: string;
  title?: string;
  description?: string;
  image?: string;
  favicon?: string;
  site?: string;

  id?: string;
}

export async function fetchLinkPreviews(
  urls: string[],
  onProgress?: (progress: {
    completed: number;
    total: number;
    current?: ICorLinkPreview;
  }) => void
): Promise<ICorLinkPreview[]> {

  let completed = 0;
  const total = urls.length;

  const normalize = (u: string) => /^https?:\/\//.test(u) ? u : `https://${u}`;

  const extractYoutubeId = (url: string) => {
    const match = url.match(/(?:youtube\.com.*v=|youtu\.be\/)([^&]+)/);
    return match ? match[1] : null;
  };

  const tasks = urls.map(async (u) => {
    const url = normalize(u);

    let result: ICorLinkPreview;

    try {
      if (url.includes('youtube.com') || url.includes('youtu.be')) {
        const id = extractYoutubeId(url);

        result = {
          url,
          title: "YouTube Video",
          image: `https://img.youtube.com/vi/${id}/hqdefault.jpg`,
          favicon: `https://www.google.com/s2/favicons?domain=youtube.com`,
          site: "YouTube"
        };
      } else {
        const api = `https://api.microlink.io/?url=${encodeURIComponent(url)}&screenshot=true`;

        const res = await fetch(api);
        const json = await res.json();
        const data = json.data;

        result = {
          url,
          title: data.title,
          description: data.description,
          image: data.screenshot?.url || data.image?.url,
          favicon:
            data.logo?.url ||
            `https://www.google.com/s2/favicons?domain=${new URL(url).hostname}`,
          site: data.publisher
        };
      }
    } catch {
      result = { url, title: url };
    }

    // 🔥 update progress
    completed++;
    onProgress?.({
      completed,
      total,
      current: result
    });

    return result;
  });

  return Promise.all(tasks);
}

// https://www.sitepoint.com/sort-an-array-of-objects-in-javascript
// Usage: ARRAY.sort(compareValues('nome'));
export function compareValues(key: any, order = 'asc') {
  // console.log(key, order);
  return function innerSort(a: any, b: any) {
    // console.log(get(a, key, null), get(b, key, null));
    // console.log(!a.hasOwnProperty(key), !b.hasOwnProperty(key));
    if (!a.hasOwnProperty(key) || !b.hasOwnProperty(key)) {
      // property doesn't exist on either object
      return 0;
    } // if 

    const varA = (typeof a[key] === 'string')
      ? desacentua(a[key]).toUpperCase() : a?.[key] ?? null;
    const varB = (typeof b[key] === 'string')
      ? desacentua(b[key]).toUpperCase() : b?.[key] ?? null;
    // console.log(varA, varB);

    let comparison = 0;
    if (varA > varB) {
      comparison = 1;
    } else if (varA < varB) {
      comparison = -1;
    } // else
    return (
      (order === 'desc') ? (comparison * -1) : comparison
    );
  };
}

export function getRandomItem<T>(arr: T[] = []): T {
  const POS = Math.floor(Math.random() * arr.length);
  return arr[POS];
}

export const getRandomNumbers = (
  qtde: number,
  min: number,
  max: number
) => {
  const RES: number[] = [];

  for (let i = 0; i < qtde; i++) {
    RES.push(randomRange(min, max));
  } // for

  return RES;
}

