export const id2date = (id: string): Date | null => {
  if (id && /^\d{8}$/.test(id)) {
    const year = parseInt(id.slice(0, 4), 10);
    const month = parseInt(id.slice(4, 6), 10);
    const day = parseInt(id.slice(6, 8), 10);

    const date = new Date(year, month - 1, day);

    // Verifica se a data construída corresponde aos valores originais
    return (date.getFullYear() === year &&
      date.getMonth() === month - 1 &&
      date.getDate() === day) ? date : null;
  }

  return null;
};

