export const grouptBy = (fn: any, list: any[] = []) => (
  (list || [])
    .reduce(
      (prev, next) => (
        {
          ...prev,
          [fn(next)]: [...(prev[fn(next)] || []), next],
        }
      ),
      {}
    )
);

