/**
 * Converte um ICorSchemaRet em uma lista plana de ICorSchemaInfo,
 * incluindo o id (caminho do grupo + nome do item).
 */
export function flattenSchema(ret: ICorSchemaRet): ICorSchemaInfo[] {
  return ret.data.flatMap((group) =>
    group.data.map((item) => ({
      ...item,
      id: `${group.id}/${item.name}`,
    })),
  );
}

export function purgeSchemasTypes(
  data: ICorSchemaRet,
  typesToPurge: TCorSchemaInfo[],
): ICorSchemaRet {
  return {
    data: data.data
      .map((group) => ({
        ...group,
        data: group.data.filter((item) => !typesToPurge.includes(item.type)),
      }))
      .filter((group) => group.data.length > 0),
  };
}

