/**
 * schemaById
 * Retorna a lista de ICorSchemaInfo de todas as entradas cujo id
 * comece com o id informado, incluindo o id de origem em cada item.
 */
export function schemaById(json: ICorSchemaRet, id: string, filter: string = ''): ICorSchemaInfo[] {
  const entries = json?.data?.filter((item) => item.id?.startsWith(id)) ?? [];
  return entries
    .flatMap((entry) =>
      (entry.data ?? []).map((info: ICorSchemaInfo) => ({ ...info, id: entry.id })),
    )
    .filter((item: ICorSchemaInfo) => item.name?.toLowerCase().includes(filter.toLowerCase()));
}

export function schemaByName(
  json: { data: ICorSchemaRet["data"] },
  name: string,
): ICorSchemaInfo | null {
  for (const entry of json?.data ?? []) {
    const found = entry.data?.find(
      (info: ICorSchemaInfo) => info.name === name,
    );
    if (found) return found;
  }
  return null;
}

export interface ICorSchemaInfoGroupByType {
  type: TCorSchemaInfo;
  data: ICorSchemaInfo[];
}

/**
 * schemaGroupByType
 * Agrupa um array de ICorSchemaInfo pelos seus respectivos tipos.
 * @param data ICorSchemaInfo[]
 * @returns ICorSchemaInfoGroupByType[]
 */
export function schemaGroupByType(
  data: ICorSchemaInfo[],
): ICorSchemaInfoGroupByType[] {
  const map = new Map<TCorSchemaInfo, ICorSchemaInfo[]>();

  for (const item of data) {
    const list = map.get(item.type) ?? [];
    list.push(item);
    map.set(item.type, list);
  }

  return Array.from(map.entries()).map(([type, data]) => ({ type, data }));
}

