export interface IParsedUrl {
  origin: string;
  params: Record<string, string | string[]>;
}

export const parseUrl = (urlString: string): IParsedUrl | null => {
  if (!(urlString || '').trim()) return null;

  const url = new URL(urlString);
  const params: Record<string, string | string[]> = {};

  // Extract query parameters
  for (const [key, value] of url.searchParams.entries()) {
    const allValues = url.searchParams.getAll(key);
    params[key] = allValues.length > 1 ? allValues : value;
  }

  return {
    origin: url.origin, // Returns e.g., "https://example.com"
    params
  };
}

