export const scrambleString = (str: string): string => {
  const arr: string[] = str.split('');
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr.join('');
}

export const strHash = (s: string): number => {
  return Math.abs(
    s.split('').reduce(
      function(a, b) {
        const A = ((a << 5) - a) + b.charCodeAt(0);
        return A & A;
      }, 0)
  );
};

export function tcenter(
  txt: string,
  len: number,
  sep: string = ' '
): string {
  txt = txt.trim();
  const L: number = len - txt.length;
  if (L > 0) {
    const L1: number = Math.trunc(L / 2);
    const L2: number = L1 + L % 2;
    // console.log(txt, len, L, L1, L2);
    return sep.repeat(L1) + txt + sep.repeat(L2);
  };
  return txt.slice(0, len);
}

export const toProperCase = (text: string): string => {
  if (text) {
    const TEXT: string = (text || '').trim();
    return TEXT.replace(
      /\w\S*/g,
      (substr) => substr.charAt(0).toUpperCase() + substr.substr(1).toLowerCase()
    );
  } else {
    return '';
  } // else
};

export function breakpoint(width: number): TCorBreakpoints {
  const entries = Object.entries(COR_BREAKPOINTS) as [TCorBreakpoints, number][];

  const sorted = entries.sort((a, b) => b[1] - a[1]);

  const found = sorted.find(([, value]) => width >= value);

  return found ? found[0] : 'xs';
}

export function colorToRgb(color: string): [number, number, number] {
  const s = color.trim().toLowerCase();

  // ── HEX ─────────────────────────────────────────────────────────────
  if (s.startsWith('#')) {
    const hex = s.slice(1);
    if (hex.length === 3) {
      return [
        parseInt(hex[0] + hex[0], 16),
        parseInt(hex[1] + hex[1], 16),
        parseInt(hex[2] + hex[2], 16),
      ];
    }
    return [
      parseInt(hex.slice(0, 2), 16),
      parseInt(hex.slice(2, 4), 16),
      parseInt(hex.slice(4, 6), 16),
    ];
  }

  // ── HSL ──────────────────────────────────────────────────────────────
  const hslMatch = s.match(/^hsla?\(\s*([\d.]+)\s*,\s*([\d.]+)%\s*,\s*([\d.]+)%/);
  if (hslMatch) {
    const h = parseFloat(hslMatch[1]) / 360;
    const sat = parseFloat(hslMatch[2]) / 100;
    const l = parseFloat(hslMatch[3]) / 100;
    return hslToRgb(h, sat, l);
  }

  // ── RGB ───────────────────────────────────────────────────────────────
  const rgbMatch = s.match(/^rgba?\(\s*([\d.]+)\s*,\s*([\d.]+)\s*,\s*([\d.]+)/);
  if (rgbMatch) {
    return [parseFloat(rgbMatch[1]), parseFloat(rgbMatch[2]), parseFloat(rgbMatch[3])];
  }

  // ── NAMED COLOR ───────────────────────────────────────────────────────
  // Render onto a canvas pixel to let the browser resolve any named color
  const ctx = document.createElement('canvas').getContext('2d')!;
  ctx.fillStyle = color;
  const resolved = ctx.fillStyle; // browser normalizes to hex or rgb(...)
  if (resolved !== color) return colorToRgb(resolved); // recurse once
  return [0, 0, 0]; // fallback: unknown → black
}

