export function fixBarcode(
  barcode: string,
  cod: any = ''
): string {
  const BARCODE: string = String(Number(barcode));
  return (
    BARCODE.length < 8
    || BARCODE === String(cod)
  )
    ? ''
    : BARCODE;
}

export function isBarcode(barcode: string): boolean {
  const BARCODE: string = `${barcode}`.replace(/[^\d]+/g, '').trim();
  return (BARCODE == barcode) && (BARCODE.length >= 8);
}

export function isCEP(cep: string): boolean {
  const CEP: string = `${cep}`.replace(/[^\d]+/g, '');
  return !!(CEP && CEP.length === 8);
}

export function isCnpj(cnpj: string): boolean {
  const CNPJ: string = `${cnpj}`.replace(/[^\d]+/g, '');

  if (!CNPJ) return false;

  if (CNPJ.length !== 14) {
    return false;
  } // if

  // Elimina CNPJs invalidos conhecidos
  if (CNPJ === '00000000000000' ||
    CNPJ === '11111111111111' ||
    CNPJ === '22222222222222' ||
    CNPJ === '33333333333333' ||
    CNPJ === '44444444444444' ||
    CNPJ === '55555555555555' ||
    CNPJ === '66666666666666' ||
    CNPJ === '77777777777777' ||
    CNPJ === '88888888888888' ||
    CNPJ === '99999999999999') {
    return false;
  } // if

  // Valida DVs
  let tamanho: number = CNPJ.length - 2;
  let soma: number = 0;
  let pos: number = tamanho - 7;
  let numeros: string = CNPJ.substring(0, tamanho);
  const DIGITOS = CNPJ.substring(tamanho);

  for (let i = tamanho; i >= 1; i--) {
    soma += +numeros.charAt(tamanho - i) * pos--;
    if (pos < 2) {
      pos = 9;
    } // if
  } // for

  let resultado: number = soma % 11 < 2 ? 0 : 11 - soma % 11;
  if (resultado !== +DIGITOS.charAt(0)) {
    return false;
  } // if

  tamanho = tamanho + 1;
  numeros = CNPJ.substring(0, tamanho);
  soma = 0;
  pos = tamanho - 7;
  for (let i = tamanho; i >= 1; i--) {
    soma += +numeros.charAt(tamanho - i) * pos--;
    if (pos < 2) {
      pos = 9;
    } // if
  } // for

  resultado = soma % 11 < 2 ? 0 : 11 - soma % 11;
  if (resultado !== +DIGITOS.charAt(1)) {
    return false;
  } // if

  return true;
}

//#endregion

export function isCpfCnpj(cpfCnpj: string): boolean {
  return isCpf(cpfCnpj) || isCnpj(cpfCnpj);
}

export function isCpf(cpf: string): boolean {
  const CPF: string = `${cpf}`.replace(/[^\d]+/g, '');
  let digitosIguais: boolean = true;

  if (!CPF) return false;

  if (CPF.length !== 11) {
    return false;
  } // if

  for (let i = 0; i < CPF.length - 1; i++) {
    if (CPF.charAt(i) !== CPF.charAt(i + 1)) {
      digitosIguais = false;
      break;
    } // if
  } // for

  if (!digitosIguais) {
    let numeros: string = CPF.substring(0, 9);
    const DIGITOS: string = CPF.substring(9);
    let soma: number = 0;

    for (let i = 10; i > 1; i--) {
      soma += +numeros.charAt(10 - i) * i;
    } // for

    let resultado: number = soma % 11 < 2 ? 0 : 11 - soma % 11;
    if (resultado !== +DIGITOS.charAt(0)) {
      return false;
    } // if

    numeros = CPF.substring(0, 10);
    soma = 0;
    for (let i = 11; i > 1; i--) {
      soma += +numeros.charAt(11 - i) * i;
    } // for

    resultado = soma % 11 < 2 ? 0 : 11 - soma % 11;
    if (resultado !== +DIGITOS.charAt(1)) {
      return false;
    } // if
    return true;
  } // if

  return false;
}

export function isEmail(email: string): boolean {
  const sQtext = '[^\\x0d\\x22\\x5c\\x80-\\xff]';
  const sDtext = '[^\\x0d\\x5b-\\x5d\\x80-\\xff]';
  const sAtom = '[^\\x00-\\x20\\x22\\x28\\x29\\x2c\\x2e\\x3a-\\x3c\\x3e\\x40\\x5b-\\x5d\\x7f-\\xff]+';
  const sQuotedPair = '\\x5c[\\x00-\\x7f]';
  const sDomainLiteral = '\\x5b(' + sDtext + '|' + sQuotedPair + ')*\\x5d';
  const sQuotedString = '\\x22(' + sQtext + '|' + sQuotedPair + ')*\\x22';
  const sDomainRef = sAtom;
  const sSubDomain = '(' + sDomainRef + '|' + sDomainLiteral + ')';
  const sWord = '(' + sAtom + '|' + sQuotedString + ')';
  const sDomain = sSubDomain + '(\\x2e' + sSubDomain + ')*';
  const sLocalPart = sWord + '(\\x2e' + sWord + ')*';
  const sAddrSpec = sLocalPart + '\\x40' + sDomain; // complete RFC822 email address spec
  const sValidEmail = '^' + sAddrSpec + '$'; // as whole string

  const reValidEmail = new RegExp(sValidEmail);

  return reValidEmail.test(email);
}

export function isFoneCel(fone: string): boolean {
  const FONE: string = `${fone}`.replace(/[^\d]+/g, '');
  return !!(!!FONE && [9, 11, 13, 14].includes(FONE.length));
}

export function isFoneFixo(fone: string): boolean {
  const FONE: string = `${fone}`.replace(/[^\d]+/g, '');
  return !!(FONE && FONE.length === 10);
}

export function isIE(ie: string): boolean {
  const IE: string = `${ie}`.replace(/[^\d]+/g, '').trim();
  return IE === ie;
}

