export interface ICorCircleSketchProps {
  color?: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | '';
  strokeWidth?: number;
  rotation?: number;
  animated?: boolean;
  animationDuration?: number;
  topPx?: number;
  leftPx?: number;
  dashed?: boolean;
  double?: boolean;
}

@Directive({
  selector: '[circleSketch]',
  standalone: true,
})
export class CorCircleSketchDirective {
  // inputs
  /** Whether to animate the circle drawing on init */
  // readonly animated = input<boolean | undefined>(undefined);
  readonly animated = input(COR_CIRCLE_SKETCH_DEFAULT.animated, { transform: booleanAttribute });

  /** Duration of the draw animation in ms */
  readonly animationDuration = input<number>(COR_CIRCLE_SKETCH_DEFAULT.animationDuration);

  /** Pass options object: <span [circleSketch]="{ color: '#2176ff', animated: true }"> */
  // readonly circleSketch = input<ICorCircleSketchProps | '' | true>('');

  /** Shorthand color override: <span circleSketch color="#2176ff"> */
  // readonly color = input<string | undefined>(undefined);
  readonly color = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ''>(COR_CIRCLE_SKETCH_DEFAULT.color);

  /** Dashed stroke variant */
  // readonly dashed = input<boolean | undefined>(undefined);
  readonly dashed = input(COR_CIRCLE_SKETCH_DEFAULT.dashed, { transform: booleanAttribute });

  /** Draw a second, lighter ellipse beneath for a double-stroke look */
  // readonly double = input<boolean | undefined>(undefined);
  readonly double = input(COR_CIRCLE_SKETCH_DEFAULT.double, { transform: booleanAttribute });

  readonly leftPx = input<number>(COR_CIRCLE_SKETCH_DEFAULT.leftPx);

  /** Rotation angle in degrees (default -2 for a natural tilt) */
  readonly rotation = input<number>(COR_CIRCLE_SKETCH_DEFAULT.rotation);

  /** Stroke weight override */
  readonly strokeWidth = input<number>(COR_CIRCLE_SKETCH_DEFAULT.strokeWidth);

  readonly topPx = input<number>(COR_CIRCLE_SKETCH_DEFAULT.topPx);

  // privates
  private readonly el = inject<ElementRef<HTMLElement>>(ElementRef);
  private readonly renderer = inject(Renderer2);
  colorVal = computed<string>(
    () => {
      const color: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | '' = this.color();
      return !!color ? cssVar(`--clr-${color}`) : 'transparent';
    }
  );
  private svg: SVGSVGElement | null = null;
  private resizeObserver: ResizeObserver | null = null;

  /** Reactive merged options — recalculated whenever any input changes */
  private readonly opts = signal<Required<ICorCircleSketchProps>>(COR_CIRCLE_SKETCH_DEFAULT);

  // constructor
  constructor() {
    // afterRenderEffect runs after every render in which tracked signals change
    afterRenderEffect(
      () => {
        this.opts.set(this.#mergeOptions());
        this.#apply();
      }
    );
  }

  // lifecycles
  ngOnDestroy(): void {
    this.#teardown();
  }

  // utils
  #mergeOptions(): Required<ICorCircleSketchProps> {
    // const input = this.circleSketch();
    // const fromInput: ICorCircleSketchProps = !!input && typeof input === 'object' ? input : {};
    // console.log({ fromInput });
    const fromInput: ICorCircleSketchProps = {};

    return {
      color: this.colorVal() ?? fromInput.color ?? COR_CIRCLE_SKETCH_DEFAULT.color,
      strokeWidth: this.strokeWidth() ?? fromInput.strokeWidth ?? COR_CIRCLE_SKETCH_DEFAULT.strokeWidth,
      rotation: this.rotation() ?? fromInput.rotation ?? COR_CIRCLE_SKETCH_DEFAULT.rotation,
      animated: this.animated() ?? fromInput.animated ?? COR_CIRCLE_SKETCH_DEFAULT.animated,
      animationDuration: this.animationDuration() ?? fromInput.animationDuration ?? COR_CIRCLE_SKETCH_DEFAULT.animationDuration,
      dashed: this.dashed() ?? fromInput.dashed ?? COR_CIRCLE_SKETCH_DEFAULT.dashed,
      double: this.double() ?? fromInput.double ?? COR_CIRCLE_SKETCH_DEFAULT.double,
      topPx: this.topPx() ?? fromInput.topPx ?? COR_CIRCLE_SKETCH_DEFAULT.topPx,
      leftPx: this.leftPx() ?? fromInput.leftPx ?? COR_CIRCLE_SKETCH_DEFAULT.leftPx,
    };
  }

  #apply(): void {
    const host = this.el.nativeElement;

    // Ensure the host is positioned so the absolute SVG overlays correctly
    const pos = getComputedStyle(host).position;
    if (pos === 'static') {
      this.renderer.setStyle(host, 'position', 'relative');
    }
    this.renderer.setStyle(host, 'display', 'inline-block');
    this.renderer.setStyle(host, 'white-space', 'nowrap');

    this.#teardown();
    this.#buildSvg();

    // Watch for size changes (e.g. font-size transitions, window resize)
    this.resizeObserver = new ResizeObserver(() => this.#updateEllipses());
    this.resizeObserver.observe(host);
  }

  #buildSvg(): void {
    const host = this.el.nativeElement;
    const opts = this.opts();
    // console.log(opts.topPx * -1);
    // console.log(opts.leftPx * -1);

    const svg = this.renderer.createElement('svg', COR_CIRCLE_SKETCH_SVG_NS) as SVGSVGElement;
    this.renderer.setAttribute(svg, 'aria-hidden', 'true');
    this.renderer.setAttribute(svg, 'focusable', 'false');
    this.renderer.setStyle(svg, 'position', 'absolute');
    // this.renderer.setStyle(svg, 'top', '-12px');
    // this.renderer.setStyle(svg, 'left', '-14px');
    this.renderer.setStyle(svg, 'top', `${opts.topPx * -1}px`);
    this.renderer.setStyle(svg, 'left', `${opts.leftPx * -1}px`);
    // this.renderer.setStyle(svg, 'width', 'calc(100% + 28px)');
    // this.renderer.setStyle(svg, 'height', 'calc(100% + 24px)');
    this.renderer.setStyle(svg, 'height', `calc(100% + ${opts.topPx * 2}px)`);
    this.renderer.setStyle(svg, 'width', `calc(100% + ${opts.leftPx * 2}px)`);
    this.renderer.setStyle(svg, 'overflow', 'visible');
    this.renderer.setStyle(svg, 'pointer-events', 'none');

    // Double ellipse (secondary, lower opacity)
    if (!!opts.double) {
      const e2 = this.#createEllipse('cor-circle-sketch-e2');
      this.renderer.setAttribute(e2, 'opacity', '0.32');
      this.renderer.setAttribute(e2, 'stroke-width', String(opts.strokeWidth * 0.4));
      this.renderer.appendChild(svg, e2);
    }

    // Primary ellipse
    const e1 = this.#createEllipse('cor-circle-sketch-e1');
    this.renderer.setAttribute(e1, 'stroke-width', String(opts.strokeWidth));
    if (!!opts.dashed) {
      this.renderer.setAttribute(e1, 'stroke-dasharray', '6 3');
    }
    this.renderer.appendChild(svg, e1);

    this.renderer.appendChild(host, svg);
    this.svg = svg;

    // Sync geometry then optionally animate
    this.#updateEllipses();

    !!opts.animated && this.#animateIn();
  }

  #createEllipse(id: string): SVGEllipseElement {
    const el = this.renderer.createElement('ellipse', COR_CIRCLE_SKETCH_SVG_NS) as SVGEllipseElement;
    this.renderer.setAttribute(el, 'id', id);
    this.renderer.setAttribute(el, 'fill', 'none');
    this.renderer.setAttribute(el, 'stroke', this.opts().color);
    this.renderer.setAttribute(el, 'stroke-linecap', 'round');
    this.renderer.setAttribute(el, 'stroke-linejoin', 'round');
    return el;
  }

  #updateEllipses(): void {
    if (!this.svg) return;
    const host = this.el.nativeElement;
    const opts = this.opts();

    const w = host.offsetWidth + 28;
    const h = host.offsetHeight + 24;
    const cx = w / 2;
    const cy = h / 2;

    this.renderer.setAttribute(this.svg, 'viewBox', `0 0 ${w} ${h}`);

    const e1 = this.svg.getElementById('cor-circle-sketch-e1') as SVGEllipseElement | null;
    const e2 = this.svg.getElementById('cor-circle-sketch-e2') as SVGEllipseElement | null;

    if (!!e1) {
      const rx = cx - 8;
      const ry = cy - 4;
      this.#setEllipseGeometry(e1, cx, cy, rx, ry, opts.rotation, opts.color);
    }

    if (!!e2) {
      const rx = cx - 12;
      const ry = cy - 7;
      this.#setEllipseGeometry(e2, cx, cy, rx, ry, -opts.rotation, opts.color);
    }
  }

  #setEllipseGeometry(
    el: SVGEllipseElement,
    cx: number, cy: number,
    rx: number, ry: number,
    rotation: number,
    color: string,
  ): void {
    this.renderer.setAttribute(el, 'cx', String(cx));
    this.renderer.setAttribute(el, 'cy', String(cy));
    this.renderer.setAttribute(el, 'rx', String(Math.max(1, rx)));
    this.renderer.setAttribute(el, 'ry', String(Math.max(1, ry)));
    this.renderer.setAttribute(el, 'transform', `rotate(${rotation}, ${cx}, ${cy})`);
    this.renderer.setAttribute(el, 'stroke', color);
  }

  #animateIn(): void {
    if (!this.svg) return;
    const opts = this.opts();
    // const duration = `${opts.animationDuration}ms`;

    this.svg.querySelectorAll('ellipse').forEach((ellipse, i) => {
      // Use a large enough dasharray to cover any ellipse circumference
      const len = 2000;
      this.renderer.setAttribute(ellipse, 'stroke-dasharray', opts.dashed ? '6 3' : String(len));
      this.renderer.setAttribute(ellipse, 'stroke-dashoffset', String(len));

      ellipse.animate(
        [{ strokeDashoffset: len }, { strokeDashoffset: 0 }],
        {
          duration: opts.animationDuration,
          delay: i * 60,
          easing: 'cubic-bezier(0.4, 0, 0.2, 1)',
          fill: 'forwards',
        },
      );
    });
  }

  /** Remove the injected SVG and stop observing */
  #teardown(): void {
    this.resizeObserver?.disconnect();
    this.resizeObserver = null;

    if (this.svg) {
      this.svg.remove();
      this.svg = null;
    }
  }
}

// models
export const COR_CURVED_UNDERLINE_CURVATURES: string[] = [
  'none',
  'default',
  'deep',
  'default-inverted',
  'deep-inverted',
] as const;

export interface ICorCurvedUnderlineProps {
  color?: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | '';
  strokeWidth?: number;
  animated?: boolean;
  animationDuration?: number;
  topPx?: number;
  leftPx?: number;
  dashed?: boolean;
  /**
   * Controls the curvature of the underline.
   * - `none`             = straight line
   * - `default`          = default curve (0.5)
   * - `deep`             = deep curve (1.0)
   * - `default-inverted` = default curve inverted (-0.5)
   * - `deep-inverted`    = deep curve inverted (-1.0)
   */
  curvature?: TCorCurvedUnderlineCurvatures;
}

export const COR_CURVED_UNDERLINE_DEFAULT: Required<ICorCurvedUnderlineProps> = {
  color: 'warning-500' as unknown as Required<ICorCurvedUnderlineProps>['color'],
  strokeWidth: 3,
  animated: true,
  animationDuration: 900,
  topPx: 4,
  leftPx: 0,
  dashed: false,
  curvature: 'default',
};

/*
 <span cor-curved-underline
       color="warning-500"
       [strokeWidth]="3"
       [animated]="true"
       [animationDuration]="700"
       [topPx]="4"
       [leftPx]="0"
       [dashed]="false"
       curvature="default"
>
*/
@Directive({
  selector: '[cor-curved-underline]',
  standalone: true,
})
export class CorCurvedUnderlineDirective {
  // inputs
  readonly color = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ''>(
    COR_CURVED_UNDERLINE_DEFAULT.color,
  );
  readonly strokeWidth = input<number>(COR_CURVED_UNDERLINE_DEFAULT.strokeWidth);
  readonly animated = input(COR_CURVED_UNDERLINE_DEFAULT.animated, { transform: booleanAttribute });
  readonly animationDuration = input<number>(COR_CURVED_UNDERLINE_DEFAULT.animationDuration);
  readonly topPx = input<number>(COR_CURVED_UNDERLINE_DEFAULT.topPx);
  readonly leftPx = input<number>(COR_CURVED_UNDERLINE_DEFAULT.leftPx);
  readonly dashed = input(COR_CURVED_UNDERLINE_DEFAULT.dashed, { transform: booleanAttribute });
  /** none | default | deep | default-inverted | deep-inverted */
  readonly curvature = input<TCorCurvedUnderlineCurvatures>(COR_CURVED_UNDERLINE_DEFAULT.curvature);

  // privates
  private readonly el = inject<ElementRef<HTMLElement>>(ElementRef);
  private readonly renderer = inject(Renderer2);

  private readonly colorVal = computed<string>(() => {
    const c = this.color();
    return c ? cssVar(`--clr-${c}`) : 'transparent';
  });

  private readonly curvatureVal = computed<number>(() => {
    return CURVATURE_MAP[this.curvature()] ?? CURVATURE_MAP['default'];
  });

  private readonly opts = signal<Required<ICorCurvedUnderlineProps>>(COR_CURVED_UNDERLINE_DEFAULT);

  private svg: SVGSVGElement | null = null;
  private resizeObserver: ResizeObserver | null = null;

  constructor() {
    afterRenderEffect(() => {
      this.opts.set(this.#mergeOptions());
      this.#apply();
    });
  }

  ngOnDestroy(): void {
    this.#teardown();
  }

  // utils
  #mergeOptions(): Required<ICorCurvedUnderlineProps> {
    const fromInput: ICorCurvedUnderlineProps = {};

    return {
      color: this.colorVal() ?? fromInput.color ?? COR_CURVED_UNDERLINE_DEFAULT.color,
      strokeWidth: this.strokeWidth() ?? fromInput.strokeWidth ?? COR_CURVED_UNDERLINE_DEFAULT.strokeWidth,
      animated: this.animated() ?? fromInput.animated ?? COR_CURVED_UNDERLINE_DEFAULT.animated,
      animationDuration: this.animationDuration() ?? fromInput.animationDuration ?? COR_CURVED_UNDERLINE_DEFAULT.animationDuration,
      topPx: this.topPx() ?? fromInput.topPx ?? COR_CURVED_UNDERLINE_DEFAULT.topPx,
      leftPx: this.leftPx() ?? fromInput.leftPx ?? COR_CURVED_UNDERLINE_DEFAULT.leftPx,
      dashed: this.dashed() ?? fromInput.dashed ?? COR_CURVED_UNDERLINE_DEFAULT.dashed,
      curvature: this.curvature() ?? fromInput.curvature ?? COR_CURVED_UNDERLINE_DEFAULT.curvature,
    };
  }

  #apply(): void {
    const host = this.el.nativeElement;
    const pos = getComputedStyle(host).position;
    if (pos === 'static') this.renderer.setStyle(host, 'position', 'relative');
    this.renderer.setStyle(host, 'display', 'inline-block');

    this.#teardown();
    this.#buildSvg();

    this.resizeObserver = new ResizeObserver(() => this.#updatePath());
    this.resizeObserver.observe(host);
  }

  #buildSvg(): void {
    const host = this.el.nativeElement;
    const opts = this.opts();

    const svg = this.renderer.createElement('svg', SVG_NS) as SVGSVGElement;
    this.renderer.setAttribute(svg, 'aria-hidden', 'true');
    this.renderer.setAttribute(svg, 'focusable', 'false');
    this.renderer.setStyle(svg, 'position', 'absolute');
    this.renderer.setStyle(svg, 'pointer-events', 'none');
    this.renderer.setStyle(svg, 'left', `${opts.leftPx}px`);
    this.renderer.setStyle(svg, 'bottom', `${-opts.topPx}px`);
    this.renderer.setStyle(svg, 'width', `calc(100% - ${opts.leftPx}px)`);
    this.renderer.setStyle(svg, 'height', `8px`);
    this.renderer.setStyle(svg, 'overflow', 'visible');

    const p1 = this.#createPath('cor-curved-underline-p1');
    this.renderer.setAttribute(p1, 'stroke-width', String(opts.strokeWidth));
    if (opts.dashed) this.renderer.setAttribute(p1, 'stroke-dasharray', '6 3');
    this.renderer.appendChild(svg, p1);

    this.renderer.appendChild(host, svg);
    this.svg = svg;

    this.#updatePath();

    if (opts.animated) this.#animateIn();
  }

  #createPath(id: string): SVGPathElement {
    const p = this.renderer.createElement('path', SVG_NS) as SVGPathElement;
    this.renderer.setAttribute(p, 'id', id);
    this.renderer.setAttribute(p, 'fill', 'none');
    this.renderer.setAttribute(p, 'stroke', this.opts().color);
    this.renderer.setAttribute(p, 'stroke-linecap', 'round');
    this.renderer.setAttribute(p, 'stroke-linejoin', 'round');
    return p;
  }

  #updatePath(): void {
    if (!this.svg) return;

    const host = this.el.nativeElement;
    const opts = this.opts();

    const w = Math.max(1, host.offsetWidth - opts.leftPx);
    const h = 8;

    this.renderer.setAttribute(this.svg, 'viewBox', `0 0 ${w} ${h}`);
    const d = this.#makeCurveD(w, h, this.curvatureVal());

    const p1 = this.svg.getElementById('cor-curved-underline-p1') as SVGPathElement | null;
    if (p1) {
      this.renderer.setAttribute(p1, 'd', d);
      this.renderer.setAttribute(p1, 'stroke', opts.color);
    }
  }

  /**
   * Builds the SVG path `d` attribute for the curved underline.
   *
   * The curve is a single quadratic Bézier:  M 0,h  Q cx,cy  w,ey
   *
   * `curvature` shifts the control-point Y:
   *   -  0    → straight line  (cy = h, ey = h)
   *   -  0.5  → default curve  (cy = 0, ey = 0.75 * h)
   *   -  1    → deep arch      (cy = -h, ey = 0.5 * h)
   *   - -0.5  → inverted default
   *   - -1    → inverted deep
   */
  #makeCurveD(w: number, h: number, curvature: number): string {
    // Control-point X stays at 20% of width (matches original CSS mask)
    const cx = 0.2 * w;
    // Control-point Y: 0 curvature = baseline (h), full (1) = above baseline (-h)
    const cy = h - curvature * 2 * h;
    // End-point Y: subtle drop proportional to curvature depth
    const ey = h - curvature * 0.5 * h;

    return `M0,${h} Q${cx},${cy} ${w},${ey}`;
  }

  #animateIn(): void {
    if (!this.svg) return;

    const opts = this.opts();
    const p = this.svg.querySelector('path');
    if (!p) return;

    const len = Math.max(1, Math.ceil(p.getTotalLength()));
    this.renderer.setAttribute(p, 'stroke-dasharray', opts.dashed ? '6 3' : String(len));
    this.renderer.setAttribute(p, 'stroke-dashoffset', String(len));

    p.animate(
      [{ strokeDashoffset: len }, { strokeDashoffset: 0 }],
      {
        duration: opts.animationDuration,
        easing: 'cubic-bezier(0.4, 0, 0.2, 1)',
        fill: 'forwards',
      },
    );
  }

  #teardown(): void {
    this.resizeObserver?.disconnect();
    this.resizeObserver = null;

    if (this.svg) {
      this.svg.remove();
      this.svg = null;
    }
  }
}

@Directive({
  selector: '[corFocus]',
  standalone: true,
})
export class CorFocusDirective {
  private readonly el = inject(ElementRef<HTMLInputElement>);

  readonly corFocus: InputSignalWithTransform<boolean, unknown> = input(true, {
    transform: booleanAttribute,
  });
  readonly focusDelay: InputSignal<number> = input(0);
  readonly focusSelect: InputSignalWithTransform<boolean, unknown> = input(
    false,
    { transform: booleanAttribute }
  );
  readonly focusDone: OutputEmitterRef<void> = output<void>();

  constructor() {
    effect(() => {
      const shouldFocus = this.corFocus();
      const delay = this.focusDelay();
      const select = this.focusSelect();

      if (!shouldFocus) return;

      // First focus attempt after the requested delay.
      setTimeout(() => {
        this.doFocus(select);

        // Second attempt 150ms later — wins the race against MatChipGrid
        // and any other Material init that steals focus after the first call.
        setTimeout(() => {
          this.doFocus(select);
          this.focusDone.emit();
        }, 150);
      }, delay);
    });
  }

  private doFocus(select: boolean): void {
    const nativeEl = this.el.nativeElement;
    if (!nativeEl?.isConnected) return;
    nativeEl.focus();
    if (select && typeof nativeEl.select === 'function') {
      nativeEl.select();
    }
  }
}

