@Directive({
  selector: '[tooltip]',
  standalone: true,
})
export class CorTooltipDirective {
  // Content
  tooltip = input<string>('', { alias: 'tooltip' });

  // Behavior
  tooltipPosition = input<TooltipPosition>('top');
  tooltipDelay = input<number>(150); // ms
  tooltipDisabled = input<boolean>(false);

  // Style (CSS custom properties)
  tooltipBorderRadius = input<string>('4px');
  tooltipFontSize = input<string>('.85rem');
  tooltipFontWeight = input<string>('400');
  tooltipBorderColor = input<string>('transparent');
  tooltipTextColor = input<string>('#fff');
  tooltipBgColor = input<string>('#1f2937');

  private readonly host = inject(ElementRef<HTMLElement>);
  private readonly renderer = inject(Renderer2);

  private tooltipEl: HTMLElement | null = null;
  private showTimeout?: ReturnType<typeof setTimeout>;
  private hideTimeout?: ReturnType<typeof setTimeout>;

  private readonly visible = signal(false);

  constructor() {
    effect(() => {
      if (this.visible() && !this.tooltipDisabled()) {
        this.createTooltip();
      } else {
        this.destroyTooltip();
      }
    });
  }

  @HostListener('mouseenter')
  @HostListener('focusin')
  onShow(): void {
    if (this.tooltipDisabled() || !this.tooltip()) return;

    clearTimeout(this.hideTimeout);
    this.showTimeout = setTimeout(() => {
      this.visible.set(true);
    }, this.tooltipDelay());
  }

  @HostListener('mouseleave')
  @HostListener('focusout')
  @HostListener('click')
  onHide(): void {
    clearTimeout(this.showTimeout);
    this.hideTimeout = setTimeout(() => {
      this.visible.set(false);
    }, 50);
  }

  @HostListener('window:scroll')
  @HostListener('window:resize')
  onReposition(): void {
    if (this.visible() && this.tooltipEl) {
      this.updatePosition();
    }
  }

  private createTooltip(): void {
    if (this.tooltipEl) return;

    const el = this.renderer.createElement('div') as HTMLElement;
    this.renderer.addClass(el, 'cor-tooltip');
    this.renderer.addClass(el, `cor-tooltip--${this.tooltipPosition()}`);

    const text = this.renderer.createText(this.tooltip());
    this.renderer.appendChild(el, text);

    // Apply CSS custom properties
    this.renderer.setStyle(el, '--cor-tooltip-border-radius', this.tooltipBorderRadius());
    this.renderer.setStyle(el, '--cor-tooltip-font-size', this.tooltipFontSize());
    this.renderer.setStyle(el, '--cor-tooltip-font-weight', this.tooltipFontWeight());
    this.renderer.setStyle(el, '--cor-tooltip-border-color', this.tooltipBorderColor());
    this.renderer.setStyle(el, '--cor-tooltip-text-color', this.tooltipTextColor());
    this.renderer.setStyle(el, '--cor-tooltip-bg-color', this.tooltipBgColor());

    this.renderer.appendChild(document.body, el);
    this.tooltipEl = el;

    this.updatePosition();

    requestAnimationFrame(() => {
      this.renderer.addClass(el, 'cor-tooltip--visible');
    });
  }

  private updatePosition(): void {
    if (!this.tooltipEl) return;

    const hostRect = this.host.nativeElement.getBoundingClientRect();
    const tooltipRect = this.tooltipEl.getBoundingClientRect();
    const gap = 8;

    let top = 0;
    let left = 0;

    switch (this.tooltipPosition()) {
      case 'top':
        top = hostRect.top - tooltipRect.height - gap;
        left = hostRect.left + hostRect.width / 2 - tooltipRect.width / 2;
        break;
      case 'bottom':
        top = hostRect.bottom + gap;
        left = hostRect.left + hostRect.width / 2 - tooltipRect.width / 2;
        break;
      case 'left':
        top = hostRect.top + hostRect.height / 2 - tooltipRect.height / 2;
        left = hostRect.left - tooltipRect.width - gap;
        break;
      case 'right':
        top = hostRect.top + hostRect.height / 2 - tooltipRect.height / 2;
        left = hostRect.right + gap;
        break;
    }

    this.renderer.setStyle(this.tooltipEl, 'position', 'fixed');
    this.renderer.setStyle(this.tooltipEl, 'top', `${Math.max(top, 0)}px`);
    this.renderer.setStyle(this.tooltipEl, 'left', `${Math.max(left, 0)}px`);
  }

  private destroyTooltip(): void {
    if (!this.tooltipEl) return;

    this.renderer.removeClass(this.tooltipEl, 'cor-tooltip--visible');

    const el = this.tooltipEl;
    setTimeout(() => {
      if (el.parentNode) {
        this.renderer.removeChild(document.body, el);
      }
    }, 150);

    this.tooltipEl = null;
  }

  ngOnDestroy(): void {
    clearTimeout(this.showTimeout);
    clearTimeout(this.hideTimeout);
    this.destroyTooltip();
  }
}

@Pipe({
  name: 'duration',
  standalone: true,
  pure: true
})
export class CorDurationPipe implements PipeTransform {

  transform(totalSeconds: number | null | undefined): string {
    return duration(totalSeconds);
  }
}

@Pipe({
  name: 'empty'
})
export class CorEmptyPipe implements PipeTransform {
  transform(val: any): boolean {
    return empty(val);
  }
}

@Pipe({
  name: 'exists'
})
export class CorExistsPipe implements PipeTransform {
  transform(val: any): boolean {
    return exists(val);
  }
}

@Pipe({
  name: 'filterBy',
  standalone: true,
  pure: true,
})
export class CorFilterByPipe implements PipeTransform {
  transform<T>(
    items: T[] | null | undefined,
    searchTerm: string | null | undefined,
    field?: keyof T,
  ): T[] {
    if (!items?.length) {
      return [];
    }

    const term = (searchTerm || '').trim().toLowerCase();

    if (!term) {
      return items;
    }

    return items.filter((item: T) => {
      const value = field ? item[field] : item;
      return String(value ?? '').toLowerCase().includes(term);
    });
  }
}

@Pipe({
  name: 'isEmptyObj'
})
export class CorIsEmpbyObjPipe implements PipeTransform {
  transform(val: any): boolean {
    return isEmptyObject(val);
  }
}

@Pipe({
  name: 'paginate',
  pure: true,
})
export class CorPaginatePipe implements PipeTransform {
  // transform<T>(items: T[], page: number, itemsPerPage: number): T[] {
  //   if (!items?.length) return [];
  //   const start = (page - 1) * itemsPerPage;
  //   const end = start + itemsPerPage;
  //   // console.log({ page, itemsPerPage, start, end });
  //   return items.slice(start, end);
  // }

  transform<T>(items: T[], pag: Partial<ICorPaginationChange>): T[] {
    if (!items?.length) return [];

    const page = pag?.page ?? 1;
    const itemsPerPage = pag?.itemsPerPage ?? items.length;

    if (page <= 0 || itemsPerPage <= 0) return items;

    const start = (page - 1) * itemsPerPage;
    const end = start + itemsPerPage;

    return items.slice(start, end);
  }
}

@Pipe({
  name: "schemaById",
  standalone: true,
  pure: true,
})
export class CorSchemaByIdPipe implements PipeTransform {
  transform(
    json: ICorSchemaRet | null | undefined,
    id: string,
    filter: string = "",
  ): ICorSchemaInfo[] {
    if (!json) return [];
    return schemaById(json, id, filter);
  }
}

@Pipe({
  name: "schemaByName",
  standalone: true,
  pure: true,
})
export class CorSchemaByNamePipe implements PipeTransform {
  transform(
    json: ICorSchemaRet | null | undefined,
    name: string,
    field?: keyof ICorSchemaInfo,
  ): any {
    if (!json) return field === "content" || !field ? "" : null;

    const found = schemaByName(json, name);
    if (!found) return field === "content" || !field ? "" : null;

    return field ? found[field] : found.content;
  }
}

@Pipe({
  name: "schemaGroupByType",
  standalone: true,
  pure: true,
})
export class CorSchemaGroupByTypePipe implements PipeTransform {
  transform(
    data: ICorSchemaInfo[] | null | undefined,
  ): ICorSchemaInfoGroupByType[] {
    if (!data) return [];
    return schemaGroupByType(data);
  }
}

@Pipe({
  name: 'sortObj',
  standalone: true,
  pure: true,
})
export class CorSortObjPipe implements PipeTransform {
  transform<T extends Record<string, any>>(
    value: T[] | null | undefined,
    key: string,
    order: 'asc' | 'desc' = 'asc'
  ): T[] {
    if (!value || !Array.isArray(value)) {
      return [];
    } // if

    return [...value].sort(compareValues(key, order));
  }
}

@Pipe({
  name: 'truncate',
  standalone: true,
  pure: true,
})
export class CorTruncatePipe implements PipeTransform {
  transform(value: string | null | undefined, length = 50, suffix = '…'): string {
    if (!value) return '';
    return value.length > length ? value.slice(0, length) + suffix : value;
  }
}

@Injectable({ providedIn: "root" })
export class CorDataService {
  private readonly usuario = "conecdata";
  private readonly repo = "uai-data";
  private readonly branch = "main";

  // constructor
  constructor(private http: HttpClient) {}

  // methods
  /**
   * getByFileName
   * @param fileName string
   * @returns Observable<T>
   */
  getByFileName<T = any>(fileName: string): Observable<T> {
    const url = `https://cdn.jsdelivr.net/gh/${this.usuario}/${this.repo}@${this.branch}/${fileName}?t=${Date.now()}`;
    return this.http.get<T>(url);
  }
}

