    const boldVal: number = COR_FONT_WEIGHTS?.[bold];
    const colorBgActiveVal: string = !!colorBg
      ? cssVar(`--clr-${colorBgActive}`)
      : "transparent";
    const colorBgVal: string = !!colorBg
      ? cssVar(`--clr-${colorBg}`)
      : "transparent";
    const colorBgHoverVal: string = !!colorBg
      ? cssVar(`--clr-${colorBgHover}`)
      : "transparent";
    const colorBorderVal: string = !!colorBorder
      ? cssVar(`--clr-${colorBorder}`)
      : "transparent";
    const colorTextVal: string = !!colorText
      ? cssVar(`--clr-${colorText}`)
      : "transparent";
    const colorTextActiveVal: string = !!colorText
      ? cssVar(`--clr-${colorTextActive}`)
      : "transparent";
    const colorTextHoverVal: string = !!colorText
      ? cssVar(`--clr-${colorTextHover}`)
      : "transparent";
    const paddingXVal: number = COR_PADDINGS?.[paddingX];
    const paddingYVal: number = COR_PADDINGS?.[paddingY];
    const roundedVal: number = COR_ROUNDEDS?.[rounded];
    const sizeBorderVal: number = COR_BORDER_SIZES?.[sizeBorder];
    const sizeFontVal: number = COR_FONT_SIZES?.[sizeFont];

    return `
      --cor-btn-group-bold: ${boldVal};
      --cor-btn-group-clr-bg: ${colorBgVal};
      --cor-btn-group-clr-bg-active: ${colorBgActiveVal};
      --cor-btn-group-clr-bg-hover: ${colorBgHoverVal};
      --cor-btn-group-clr-border: ${colorBorderVal};
      --cor-btn-group-clr-text: ${colorTextVal};
