      --cor-btn-group-padding-y: ${paddingYVal}rem;
      --cor-btn-group-rounded: ${roundedVal}rem;
      --cor-btn-group-size-border: ${sizeBorderVal}px;
      --cor-btn-group-size-font: ${sizeFontVal}rem;
`
      .trim()
      .replace("\n", "");
  });

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // constructor
  constructor() {
    // effect(() => this.#applyPositionTokens());

    effect(() => {
      const buttons = this.buttons() || [];
      const off: boolean = !!this.off();
      // console.log({ off });

      buttons.forEach((btn: CorBtnGroupBtnComponent, i: number) => {
        const isSolo: boolean = buttons.length === 1;
        const isFirst: boolean = i === 0;
        const isLast: boolean = i === buttons.length - 1;

        btn._position.set(
          isSolo ? "solo" : isFirst ? "first" : isLast ? "last" : "middle",
        );
        btn._groupDisabled.set(off);
      });
    });
  }
}

