  | TCorCtaColorIds
  | TCorThemesIds
  | "";

export interface IChartItem {
  key: string;
  value: number;
  percentage?: number;
  color?: TChartColor;
}

export interface IChartTypeConfig {
  showLegendOnChart?: boolean;
  showLegendPanel?: boolean;
  showLegendValues?: boolean;
  colorBgChips?: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorGridline?: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorTextChips?: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorTracks?: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  gridSteps?: number;
  gridValuesPosition?: TGridValuesPosition;
  showTitle?: boolean;
  showTotal?: boolean;
  showGrid?: boolean;
  decimalPlaces?: number;
  showHoverEffect?: boolean;
}

export interface IChartConfig extends IChartTypeConfig {
  title?: string;
  colorBorder?: TChartColor; // ADICIONADO
  widthBorderPx?: number; // ADICIONADO
  byType?: Partial<Record<TChartType, IChartTypeConfig>>;
}

