@Component({
  selector: "cor-chart",
  standalone: true,
  imports: [CommonModule],
  templateUrl: "./chart.html",
  styleUrls: ["./chart.scss"],
})
export class CorChartComponent {
  // ---------- Injects ----------
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // ---------- Inputs (signal-based) ----------
  type = input<TChartType>("bar");
  items = input<IChartItem[]>([]);
  config = input<IChartConfig | undefined>(undefined);

  // ---------- Inputs individuais (prioridade sobre `config`) ----------
  ignoreEmpty = input<boolean>(false);
  title = input<string | undefined>(undefined);
  showLegendOnChart = input<boolean | undefined>(undefined);
  showLegendPanel = input<boolean | undefined>(undefined);
  showLegendValues = input<boolean | undefined>(undefined);
  showTitle = input<boolean | undefined>(undefined);
  showTotal = input<boolean | undefined>(undefined);
  showGrid = input<boolean | undefined>(undefined);
  gridValuesPosition = input<TGridValuesPosition | undefined>(undefined);
  showHoverEffect = input<boolean | undefined>(undefined);
  colorBorder = input<TChartColor | undefined>(undefined);
  widthBorderPx = input<number | undefined>(undefined);
  colorGridline = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" | undefined
  >(undefined);

  // ---------- State ----------
  hoveredKey = signal<string | null>(null);

  // ---------- Privates ----------
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // ---------- Derived config ----------
  resolvedConfig: Signal<IChartTypeConfig> = computed(() => {
    const type = this.type();
    const globalCfg = this.config() ?? {};
    const typeCfg = globalCfg.byType?.[type] ?? {};

    return {
      showLegendOnChart:
        this.showLegendOnChart() ??
        typeCfg.showLegendOnChart ??
        globalCfg.showLegendOnChart ??
        CHART_CONFIG_DEFAULT.showLegendOnChart,
      showLegendPanel:
        this.showLegendPanel() ??
        typeCfg.showLegendPanel ??
        globalCfg.showLegendPanel ??
        CHART_CONFIG_DEFAULT.showLegendPanel,
      showLegendValues:
        this.showLegendValues() ??
        typeCfg.showLegendValues ??
        globalCfg.showLegendValues ??
        CHART_CONFIG_DEFAULT.showLegendValues,
      colorBgChips:
        typeCfg.colorBgChips ??
        globalCfg.colorBgChips ??
        CHART_CONFIG_DEFAULT.colorBgChips,
      colorGridline:
        this.colorGridline() ??
        typeCfg.colorGridline ??
        globalCfg.colorGridline ??
        CHART_CONFIG_DEFAULT.colorGridline,
      colorTextChips:
        typeCfg.colorTextChips ??
        globalCfg.colorTextChips ??
        CHART_CONFIG_DEFAULT.colorTextChips,
      colorTracks:
        typeCfg.colorTracks ??
        globalCfg.colorTracks ??
        CHART_CONFIG_DEFAULT.colorTracks,
      gridSteps:
        typeCfg.gridSteps ??
        globalCfg.gridSteps ??
        CHART_CONFIG_DEFAULT.gridSteps,
      gridValuesPosition:
        this.gridValuesPosition() ??
        typeCfg.gridValuesPosition ??
        globalCfg.gridValuesPosition ??
        CHART_CONFIG_DEFAULT.gridValuesPosition,
      decimalPlaces:
        typeCfg.decimalPlaces ??
        globalCfg.decimalPlaces ??
        CHART_CONFIG_DEFAULT.decimalPlaces,
      showTitle:
        this.showTitle() ??
        typeCfg.showTitle ??
        globalCfg.showTitle ??
        CHART_CONFIG_DEFAULT.showTitle,
      showTotal:
        this.showTotal() ??
        typeCfg.showTotal ??
        globalCfg.showTotal ??
        CHART_CONFIG_DEFAULT.showTotal,
      showGrid:
        this.showGrid() ??
        typeCfg.showGrid ??
        globalCfg.showGrid ??
        CHART_CONFIG_DEFAULT.showGrid,
      showHoverEffect:
        this.showHoverEffect() ??
        typeCfg.showHoverEffect ??
        globalCfg.showHoverEffect ??
        CHART_CONFIG_DEFAULT.showHoverEffect,
    };
  });

  totalValue = computed(() =>
    this.visibleItems().reduce((sum, item) => sum + item.value, 0),
  );

  chartTitle = computed(() => this.title() ?? this.config()?.title ?? "");

  maxValue = computed(() => {
    const values = this.visibleItems().map((i) => i.value);
    return values.length ? Math.max(...values) : 1;
  });

  // ---------- Derived items ----------
  visibleItems = computed<IChartItem[]>(() => {
    const all = this.items();
    return this.ignoreEmpty() ? all.filter((item) => item.value > 0) : all;
  });

  /** Geometria angular (início/fim em radianos) de cada fatia do pie/donut */
  private sliceGeometries = computed<ISliceGeometry[]>(() => {
    const items = this.visibleItems();
    const total = items.reduce((sum, i) => sum + i.value, 0);

    if (total <= 0) return [];

    let cumulative = 0;
    const fullCircle = Math.PI * 2;

    return items.map((item) => {
      const startAngle = (cumulative / total) * fullCircle - Math.PI / 2;
      cumulative += item.value;
      const endAngle = (cumulative / total) * fullCircle - Math.PI / 2;
      return { key: item.key, startAngle, endAngle };
    });
  });

  private getGeometry(item: IChartItem): ISliceGeometry | null {
    return this.sliceGeometries().find((g) => g.key === item.key) ?? null;
  }

  // ---------- Border (divisão entre fatias) ----------

  resolvedBorderColor = computed<TChartColor>(() => {
    this.isDarkMode();
    return (
      this.colorBorder() ??
      this.config()?.colorBorder ??
      CHART_BORDER_COLOR_DEFAULT
    );
  });

  resolveContrastColorVar(item: IChartItem, idx: number): string {
    this.isDarkMode();

    const colorVar = this.resolveColorVar(item, idx);
    const match = colorVar.match(/var\((--clr-[a-zA-Z]+)-\d+\)/);
    if (match) {
      return `var(${match[1]}-contrast)`;
    }
    return "#fff";
  }

  resolvedBorderWidthPx = computed<number>(
    () =>
      this.widthBorderPx() ??
      this.config()?.widthBorderPx ??
      CHART_BORDER_WIDTH_DEFAULT,
  );

  resolveTokenVar(color: TChartColor): string {
    this.isDarkMode();

    const match = color.match(/^(.*)-(\d{2,3})$/);
    if (!match) return color;
    const [, name, shade] = match;
    return `var(--clr-${name}-${shade})`;
  }

  borderColorVar = computed<string>(() => {
    this.isDarkMode();
    return this.resolveTokenVar(this.resolvedBorderColor());
  });

  borderWidthPx = computed<number>(() => this.resolvedBorderWidthPx());

  // ---------- Color resolution ----------

  resolveColor(item: IChartItem, index: number): TChartColor {
    this.isDarkMode();

    return item.color && item.color !== ""
      ? item.color
      : COR_CHART_DEFAULT[index % COR_CHART_DEFAULT.length];
  }

  resolveColorVar(item: IChartItem, index: number): string {
    this.isDarkMode();

    const palette = [
      "primary",
      "base",
      "success",
      "warning",
      "info",
      "cta",
      "danger",
    ];
    const key = palette[index % palette.length];
    return `var(--clr-${key}-500)`;
  }

  resolveChipBg(item: IChartItem, idx: number): string {
    this.isDarkMode();

    const configColor = this.resolvedConfig().colorBgChips;
    return configColor
      ? `var(--clr-${configColor})`
      : this.resolveColorVar(item, idx);
  }

  resolveChipText(item: IChartItem, idx: number): string {
    this.isDarkMode();

    const configColor = this.resolvedConfig().colorTextChips;
    return configColor
      ? `var(--clr-${configColor})`
      : this.resolveContrastColorVar(item, idx);
  }

  resolveTrackColor(): string {
    this.isDarkMode();

    const trackColor = this.resolvedConfig().colorTracks;
    return trackColor ? `var(--clr-${trackColor})` : "transparent";
  }

  /** Cor resolvida das linhas de grid, com fallback caso colorGridline seja '' */
  resolveGridColor(): string {
    this.isDarkMode();

    const gridColor = this.resolvedConfig().colorGridline;
    return gridColor ? `var(--clr-${gridColor})` : "rgba(0, 0, 0, 0.08)";
  }

  showTracks(): boolean {
    const type = this.type();
    return (
      (type === "bar" || type === "column") &&
      !!this.resolvedConfig().colorTracks
    );
  }

  private formatGridValue(value: number): string {
    // Se o valor máximo é inteiro pequeno (ex: 1), evita steps fracionários redundantes
    if (Number.isInteger(value)) {
      return value.toString();
    }
    return value.toFixed(this.resolvedConfig().decimalPlaces ?? 1);
  }

  private resolveGridSteps(max: number, requestedSteps: number): number {
    if (max <= 0) return 1;
    // Não gera mais steps do que valores inteiros distintos possíveis
    return Math.min(requestedSteps, Math.max(1, Math.floor(max)));
  }

  /** Linhas de grid com posição (%) e valor correspondente, indo de 0 a maxValue */
  gridLines = computed<{ pos: number; value: string }[]>(() => {
    const max = this.maxValue();
    const steps = this.resolveGridSteps(
      max,
      this.resolvedConfig().gridSteps ?? 5,
    );

    const rawLines = Array.from({ length: steps + 1 }, (_, i) => {
      const pos = (i / steps) * 100;
      const value = (max * i) / steps;
      return { pos, value: this.formatGridValue(value) };
    });

    const seen = new Set<string>();
    return rawLines.filter((line) => {
      if (seen.has(line.value)) return false;
      seen.add(line.value);
      return true;
    });
  });

  /** true quando os valores do grid devem ser exibidos (posição diferente de 'none') */
  showGridValues = computed<boolean>(
    () =>
      this.resolvedConfig().showGrid === true &&
      this.resolvedConfig().gridValuesPosition !== "none",
  );

  gridValuesPositionResolved = computed<TGridValuesPosition>(() => {
    const pos = this.resolvedConfig().gridValuesPosition;
    return pos === "none" ? "none" : (pos ?? "end");
  });

  // ---------- Size / Value formatting ----------

  getBarSize(item: IChartItem): number {
    if (item.percentage != null) return item.percentage;
    const max = this.maxValue();
    return max > 0 ? (item.value / max) * 100 : 0;
  }

  formatValue(item: IChartItem): string {
    if (item.percentage !== undefined && item.percentage !== null) {
      return `${item.percentage}%`;
    }
    return `${item.value}`;
  }

  // ---------- Hover handling ----------

  onItemHover(item: IChartItem): void {
    if (!this.resolvedConfig().showHoverEffect) return;
    this.hoveredKey.set(item.key);
  }

  onItemLeave(): void {
    if (!this.resolvedConfig().showHoverEffect) return;
    this.hoveredKey.set(null);
  }

  isHovered(item: IChartItem): boolean {
    return (
      this.resolvedConfig().showHoverEffect === true &&
      this.hoveredKey() === item.key
    );
  }

  isDimmed(item: IChartItem): boolean {
    const hovered = this.hoveredKey();
    return (
      this.resolvedConfig().showHoverEffect === true &&
      hovered !== null &&
      hovered !== item.key
    );
  }

  // ---------- Geometry (pie/donut) ----------

  private polarToCartesian(
    cx: number,
    cy: number,
    radius: number,
    angleRad: number,
  ): { x: number; y: number } {
    return {
      x: cx + radius * Math.cos(angleRad),
      y: cy + radius * Math.sin(angleRad),
    };
  }

  getSlicePath(item: IChartItem): string {
    const geo = this.getGeometry(item);
    if (!geo) return "";

    const { startAngle, endAngle } = geo;
    const isFullCircle = endAngle - startAngle >= Math.PI * 2 - 0.0001;
    const outer = OUTER_RADIUS;
    const isDonut = this.type() === "donut";
    const inner = isDonut ? DONUT_INNER_RADIUS : 0;

    if (isFullCircle) {
      const p1 = this.polarToCartesian(CENTER_X, CENTER_Y, outer, startAngle);
      const p2 = this.polarToCartesian(
        CENTER_X,
        CENTER_Y,
        outer,
        startAngle + Math.PI,
      );

      if (!isDonut) {
        return [
          `M ${p1.x} ${p1.y}`,
          `A ${outer} ${outer} 0 1 1 ${p2.x} ${p2.y}`,
          `A ${outer} ${outer} 0 1 1 ${p1.x} ${p1.y}`,
          "Z",
        ].join(" ");
      }

      const ip1 = this.polarToCartesian(CENTER_X, CENTER_Y, inner, startAngle);
      const ip2 = this.polarToCartesian(
        CENTER_X,
        CENTER_Y,
        inner,
        startAngle + Math.PI,
      );
      return [
        `M ${p1.x} ${p1.y}`,
        `A ${outer} ${outer} 0 1 1 ${p2.x} ${p2.y}`,
        `A ${outer} ${outer} 0 1 1 ${p1.x} ${p1.y}`,
        `M ${ip1.x} ${ip1.y}`,
        `A ${inner} ${inner} 0 1 0 ${ip2.x} ${ip2.y}`,
        `A ${inner} ${inner} 0 1 0 ${ip1.x} ${ip1.y}`,
        "Z",
      ].join(" ");
    }

    const largeArc = endAngle - startAngle > Math.PI ? 1 : 0;

    const outerStart = this.polarToCartesian(
      CENTER_X,
      CENTER_Y,
      outer,
      startAngle,
    );
    const outerEnd = this.polarToCartesian(CENTER_X, CENTER_Y, outer, endAngle);

    if (!isDonut) {
      return [
        `M ${CENTER_X} ${CENTER_Y}`,
        `L ${outerStart.x} ${outerStart.y}`,
        `A ${outer} ${outer} 0 ${largeArc} 1 ${outerEnd.x} ${outerEnd.y}`,
        "Z",
      ].join(" ");
    }

    const innerStart = this.polarToCartesian(
      CENTER_X,
      CENTER_Y,
      inner,
      endAngle,
    );
    const innerEnd = this.polarToCartesian(
      CENTER_X,
      CENTER_Y,
      inner,
      startAngle,
    );

    return [
      `M ${outerStart.x} ${outerStart.y}`,
      `A ${outer} ${outer} 0 ${largeArc} 1 ${outerEnd.x} ${outerEnd.y}`,
      `L ${innerStart.x} ${innerStart.y}`,
      `A ${inner} ${inner} 0 ${largeArc} 0 ${innerEnd.x} ${innerEnd.y}`,
      "Z",
    ].join(" ");
  }

  private getLabelRadius(): number {
    if (this.type() === "donut") {
      return (OUTER_RADIUS + DONUT_INNER_RADIUS) / 2;
    }
    return OUTER_RADIUS * LABEL_RADIUS_RATIO;
  }

  getLabelX(item: IChartItem): number {
    const geo = this.getGeometry(item);
    if (!geo) return CENTER_X;
    const midAngle = (geo.startAngle + geo.endAngle) / 2;
    const radius = this.getLabelRadius();
    return this.polarToCartesian(CENTER_X, CENTER_Y, radius, midAngle).x;
  }

  getLabelY(item: IChartItem): number {
    const geo = this.getGeometry(item);
    if (!geo) return CENTER_Y;
    const midAngle = (geo.startAngle + geo.endAngle) / 2;
    const radius = this.getLabelRadius();
    return this.polarToCartesian(CENTER_X, CENTER_Y, radius, midAngle).y;
  }

  trackByKey(_index: number, item: IChartItem): string {
    return item.key;
  }

  hasVisibleSlice(item: IChartItem): boolean {
    const geo = this.getGeometry(item);
    if (!geo) return false;
    return geo.endAngle - geo.startAngle > 0.001;
  }

  getLabelFontSize(item: IChartItem): number {
    const geo = this.getGeometry(item);
    if (!geo) return 6;
    const angleDeg = ((geo.endAngle - geo.startAngle) * 180) / Math.PI;

    if (angleDeg < 10) return 3.5;
    if (angleDeg < 20) return 4.5;
    return 6;
  }
}

