@Component({
  selector: "cor-circular-progress",
  standalone: true,
  imports: [
    // modules
    CommonModule,
    // pipes
    DecimalPipe,
  ],
  templateUrl: "./circular-progress.html",
  styleUrl: "./circular-progress.scss",
})
export class CorCircularProgressComponent {
  // inputs
  boldCaption = input<TCorFontWeights>(
    COR_CIRCULAR_PROGRESS_DEFAULT?.boldCaption,
  );
  boldPercent = input<TCorFontWeights>(
    COR_CIRCULAR_PROGRESS_DEFAULT?.boldPercent,
  );
  caption = input<string>(COR_CIRCULAR_PROGRESS_DEFAULT.caption);
  colorBg = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_CIRCULAR_PROGRESS_DEFAULT?.colorBg,
  );
  colorProgress = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_CIRCULAR_PROGRESS_DEFAULT?.colorProgress);
  colorText = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_CIRCULAR_PROGRESS_DEFAULT.colorText,
  );
  gap = input<TCorBsSpacings>(COR_CIRCULAR_PROGRESS_DEFAULT.gap);
  max = input<number>(COR_CIRCULAR_PROGRESS_DEFAULT.max);
  min = input<number>(COR_CIRCULAR_PROGRESS_DEFAULT.min);
  opacityCaption = input<TCorOpacities>(
    COR_CIRCULAR_PROGRESS_DEFAULT?.opacityCaption,
  );
  opacityPercent = input<TCorOpacities>(
    COR_CIRCULAR_PROGRESS_DEFAULT?.opacityPercent,
  );
  semi = input(COR_CIRCULAR_PROGRESS_DEFAULT.semi, {
    transform: booleanAttribute,
  });
  size = input<number>(COR_CIRCULAR_PROGRESS_DEFAULT.size);
  sizeFontCaption = input<TCorFontSizes>(
    COR_CIRCULAR_PROGRESS_DEFAULT?.sizeFontCaption,
  );
  sizeFontPercent = input<TCorFontSizes>(
    COR_CIRCULAR_PROGRESS_DEFAULT?.sizeFontPercent,
  );
  thickness = input<number>(COR_CIRCULAR_PROGRESS_DEFAULT.thickness);
  value = input<number>(COR_CIRCULAR_PROGRESS_DEFAULT.value);

  // publics
  // Geometry
  radius = 50;

  // Full circle circumference
  fullCircumference = computed(() => 2 * Math.PI * this.radius);

  // Semi circle uses half circumference
  circumference = computed(() =>
    this.semi() ? this.fullCircumference() / 2 : this.fullCircumference(),
  );

  // Percentage
  percent = computed(() => {
    const min = this.min();
    const max = this.max();
    const val = Math.min(max, Math.max(min, this.value()));
    const range = max - min || 1;
    return ((val - min) / range) * 100;
  });

  // Stroke offset
  offset = computed(
    () => this.circumference() - (this.percent() / 100) * this.circumference(),
  );

  // ViewBox depending on mode
  viewBox = computed(() => (this.semi() ? "0 0 120 60" : "0 0 120 120"));

  // Rotation fix for top half semicircle
  rotation = computed(() =>
    this.semi() ? "rotate(180 60 60)" : "rotate(-90 60 60)",
  );

  protected styles = computed<string>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const size: number = this.size();
    const colorBg: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorBg();
    const colorProgress:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorProgress();
    // console.log({ colorBg, colorText });

    const colorBgVal: string = !!colorBg
      ? cssVar(`--clr-${colorBg}`)
      : "transparent";
    const colorProgressVal: string = !!colorProgress
      ? cssVar(`--clr-${colorProgress}`)
      : "transparent";

    return `
      --cor-circular-progress-size: ${size}px;
      --cor-circular-progress-color-bg: ${colorBgVal};
      --cor-circular-progress-color-progress: ${colorProgressVal};
`
      .trim()
      .replace("\n", "");
  });

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);
}

