export interface ICorColorSelProps {
  colorId: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  exceptions: TCorColorSelExceptions[];
  heightPx: number;
  off: boolean;
  repeated: boolean;
  rounded: TCorRoundeds;
  sizeBorderActive: TCorBorderSizes;
}

export const COR_COLOR_SEL_DEFAULT: ICorColorSelProps = {
  colorId: "",
  exceptions: [],
  heightPx: 32,
  off: false,
  repeated: true,
  rounded: "rounded-none",
  sizeBorderActive: "border-2",
};

@Component({
  selector: "cor-color-sel",
  imports: [
    // modules
    CommonModule,
  ],
  templateUrl: "./color-sel.html",
  styleUrl: "./color-sel.scss",
})
export class CorColorSelComponent {
  // viewchilds
  @ViewChild("corColorSel") colorSelRef!: ElementRef<HTMLDivElement>;

  // inputs
  colorId = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_COLOR_SEL_DEFAULT.colorId,
  );
  exceptions = input<TCorColorSelExceptions[]>(
    COR_COLOR_SEL_DEFAULT.exceptions,
  );
  heightPx = input<number>(COR_COLOR_SEL_DEFAULT.heightPx);
  off = input(COR_COLOR_SEL_DEFAULT.off, { transform: booleanAttribute });
  repeated = input(COR_COLOR_SEL_DEFAULT.repeated, {
    transform: booleanAttribute,
  });
  rounded = input<TCorRoundeds>(COR_COLOR_SEL_DEFAULT.rounded);
  sizeBorderActive = input<TCorBorderSizes>(
    COR_COLOR_SEL_DEFAULT.sizeBorderActive,
  );

  // outputs
  colorId$ = output<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">();
  colorInfo$ = output<ICorColorSelInfo>();

  // publics - styles
  protected styles = computed<string>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const sizeBorderActive: TCorBorderSizes = this.sizeBorderActive();
    const heightPx: number = this.heightPx();

    const sizeBorderActiveVal: number = COR_BORDER_SIZES?.[sizeBorderActive];

    return `
--cor-color-sel-size-border: ${sizeBorderActiveVal}px;
--cor-color-sel-height-px: ${heightPx}px;
`
      .trim()
      .replace("\n", "");
  });

  // publics
  data = computed<ICorColorSelInfo[]>(() => {
    // const dark: boolean = !!this.dark();
    const repeated: boolean = !!this.repeated();
    const exceptions: TCorColorSelExceptions[] = this.exceptions() || [];
    // console.log(JSON.stringify(exceptions));
    const showContrasts = !exceptions.includes("contrasts");
    const colorsIdsCta: string[] = COR_BASE_COLOR_IDS.filter((c: string) =>
      !!showContrasts ? true : !c.includes("contrast"),
    );
    const colorsIds: string[] = COR_CTA_COLOR_IDS.filter((c: string) =>
      !!showContrasts ? true : !c.includes("contrast"),
    );
    const primaryIds: string[] = ["primary-400", "primary-500", "primary-600"];
    !!showContrasts && primaryIds.push("primary-contrast");
    const secondaryIds: string[] = [
      "secondary-400",
      "secondary-500",
      "secondary-600",
    ];
    !!showContrasts && secondaryIds.push("secondary-contrast");
    const successIds: string[] = ["success-400", "success-500", "success-600"];
    !!showContrasts && successIds.push("success-contrast");
    const dangerIds: string[] = ["danger-400", "danger-500", "danger-600"];
    !!showContrasts && dangerIds.push("danger-contrast");
    const warningIds: string[] = ["warning-400", "warning-500", "warning-600"];
    !!showContrasts && warningIds.push("warning-contrast");
    const infoIds: string[] = ["info-400", "info-500", "info-600"];
    !!showContrasts && infoIds.push("info-contrast");
    const lightIds: string[] = ["light-400", "light-500", "light-600"];
    !!showContrasts && lightIds.push("light-contrast");
    const darkIds: string[] = ["dark-400", "dark-500", "dark-600"];
    !!showContrasts && darkIds.push("dark-contrast");

    let colorsIdsList: string[] = [];
    !exceptions.includes("none") && colorsIdsList.push("");
    !exceptions.includes("base") && colorsIdsList.push(...colorsIds);
    !exceptions.includes("cta") && colorsIdsList.push(...colorsIdsCta);
    !exceptions.includes("primary") && colorsIdsList.push(...primaryIds);
    !exceptions.includes("secondary") && colorsIdsList.push(...secondaryIds);
    !exceptions.includes("success") && colorsIdsList.push(...successIds);
    !exceptions.includes("danger") && colorsIdsList.push(...dangerIds);
    !exceptions.includes("warning") && colorsIdsList.push(...warningIds);
    !exceptions.includes("info") && colorsIdsList.push(...infoIds);
    !exceptions.includes("light") && colorsIdsList.push(...lightIds);
    !exceptions.includes("dark") && colorsIdsList.push(...darkIds);

    // console.log({ showContrasts, exceptions, colorsIdsList });
    const colors: ICorColorSelInfo[] = uniqueListBy(
      colorsIdsList.map((id: string) => {
        const clr: string = !!id ? cssVar(`--clr-${id}`) : "transparent";
        return {
          id,
          clr: clr,
          luminance: luminance(clr),
        };
      }),
      !!repeated ? "id" : "clr",
    );
    // console.log({ colorsIdsList, colors });

    return colors;
  });
  isStacked = signal<boolean>(false);

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );
  #resizeObserver!: ResizeObserver;

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // lifecycles
  ngAfterViewInit() {
    this.#resizeObserver = new ResizeObserver((entries) => {
      const width = entries[0].contentRect.width;
      const totalMinWidth =
        this.data().length * MIN_SWATCH_WIDTH; /* + 2 */ /* + 4 */
      // console.log({ width, totalMinWidth });
      this.isStacked.set(width < totalMinWidth /* + 32 */);
    });

    this.#resizeObserver.observe(this.colorSelRef.nativeElement);
  }

  ngOnDestroy() {
    this.#resizeObserver.disconnect();
  }
}

