    const boldDescription: TCorFontWeights = this.boldDescription();
    const colorBorder: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorBorder();
    const colorCollapsedBg:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorCollapsedBg();
    const colorCollapsedBgHover:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorCollapsedBgHover();
    const colorCollapsedBorderHover:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorCollapsedBorderHover();
    const colorCollapsedText:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorCollapsedText();
    const colorCollapsedTextHover:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorCollapsedTextHover();
    const colorInfoBg: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorInfoBg();
    const colorInfoBorderTop:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorInfoBorderTop();
    const colorInfoText:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorInfoText();
    const gap: TCorBsSpacings = this.gap();
    const heightVerticalCollapsedPanelPx: number =
      this.heightVerticalCollapsedPanelPx();
    const heightVerticalExpandedPanelPx: number =
      this.heightVerticalExpandedPanelPx();
    const heightHorizontalPanelPx: number = this.heightHorizontalPanelPx();
    const opacityDescription: number = this.opacityDescription();
    const opacityExtras: TCorOpacities = this.opacityExtras();
    const opacityImgCollapsed: TCorOpacities = this.opacityImgCollapsed();
