    const paddingInfoY: Exclude<TCorSpacings, "auto"> = this.paddingInfoY();
    const rounded: TCorRoundeds = this.rounded();
    const shadow: TCorBoxShadows = this.shadow();
    const sizeBorder: TCorBorderSizes = this.sizeBorder();
    const sizeFontCaption: TCorFontSizes = this.sizeFontCaption();
    const sizeFontDescription: TCorFontSizes = this.sizeFontDescription();
