    // vals
    const boldCaptionVal: number = COR_FONT_WEIGHTS?.[boldCaption];
    const boldDescriptionVal: number = COR_FONT_WEIGHTS?.[boldDescription];
    const colorBorderVal: string = !!colorBorder
      ? cssVar(`--clr-${colorBorder}`)
