--cor-expandable-panels-height-vertical-collapsed: ${heightVerticalCollapsedPanelPx}px;
--cor-expandable-panels-height-vertical-expanded: ${heightVerticalExpandedPanelPx}px;
--cor-expandable-panels-clr-border: ${colorBorderVal};
--cor-expandable-panels-clr-collapsed-bg: ${colorCollapsedBgVal};
--cor-expandable-panels-clr-collapsed-text: ${colorCollapsedTextVal};
--cor-expandable-panels-clr-collapsed-bg-hover: ${colorCollapsedBgHoverVal};
--cor-expandable-panels-clr-collapsed-text-hover: ${colorCollapsedTextHoverVal};
--cor-expandable-panels-clr-border-hover: ${colorCollapsedBorderHoverVal};
--cor-expandable-panels-clr-info-bg: ${colorInfoBgVal};
--cor-expandable-panels-clr-info-border-top: ${colorInfoBorderTopVal};
--cor-expandable-panels-clr-info-text: ${colorInfoTextVal};
--cor-expandable-panels-padding-info-x: ${paddingInfoXVal}rem;
--cor-expandable-panels-padding-info-y: ${paddingInfoYVal}rem;
--cor-expandable-panels-rounded: ${roundedVal}rem;
--cor-expandable-panels-shadow: ${shadowVal};
--cor-expandable-panels-size-border: ${sizeBorderVal}px;
--cor-expandable-panels-width-horizontal-collapsed: ${widthHorizontalCollapsedPanelPx}px;
--cor-expandable-panels-width-expanded: ${widthExpandedPanelPx}px;
`
