  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // constructor
  constructor() {
    effect(() => {
      const panelList = this.panels();
      this.bindPanelOutputs(panelList);
      this.syncPanelStates(panelList);
    });
  }

  // lifecycles
  ngAfterContentInit(): void {
    const def = this.defaultExpanded();
    this.expandedIndex.set(def >= 0 ? def : 0);
    this.syncPanelStates(this.panels());
  }

  // ─── Private ─────────────────────────────────────────────────────────────
  private bindPanelOutputs(
    panelList: readonly CorExpandablePanelComponent[],
  ): void {
    for (const [panel, unsub] of this.subscriptionMap) {
      if (!panelList.includes(panel)) {
        unsub();
        this.subscriptionMap.delete(panel);
      }
    }
    panelList.forEach((panel, index) => {
      if (this.subscriptionMap.has(panel)) return;
      const sub = panel.toggleRequested.subscribe(() => this.openPanel(index));
      this.subscriptionMap.set(panel, () => sub.unsubscribe());
    });
  }

  private syncPanelStates(
    panelList: readonly CorExpandablePanelComponent[],
  ): void {
    const active = this.expandedIndex();
    const vertical = this.orientation() === "vertical";

    panelList.forEach((panel, index) => {
      panel.isExpanded.set(index === active);
      panel.position.set(index + 1);
      panel.chevronAngle.set(this.computeChevron(index, active, vertical));
      // showPosition / showChevron are read directly from the group's inputs
      // by the panel via the injected parent reference — no push needed.
    });
  }

  /**
   * Compute chevron rotation so the arrow points toward the open panel.
   * Horizontal: left-of-open → 0° (right), right-of-open → 180° (left)
   * Vertical:   above-open → 90° (down),   below-open → 270° (up)
   */
  private computeChevron(
    index: number,
    active: number,
    vertical: boolean,
  ): number {
    if (vertical) return index < active ? 90 : 270;
    return index < active ? 0 : 180;
  }

  // ─── Public API ──────────────────────────────────────────────────────────

  openPanel(index: number): void {
    const panelList = this.panels();
    if (index < 0 || index >= panelList.length) return;
    this.expandedIndex.set(index);
    this.syncPanelStates(panelList);
  }

  getExpandedIndex(): number {
    return this.expandedIndex();
  }
}

@Component({
  selector: "cor-expandable-panel",
  standalone: true,
  imports: [CommonModule],
  changeDetection: ChangeDetectionStrategy.OnPush,
  templateUrl: "./expandable-panel.html",
  styleUrls: ["./expandable-panel.scss"],
})
export class CorExpandablePanelComponent {
  caption = input.required<string>();
  image = input.required<string>();
  description = input<string>("");

  // ── Injected parent — provides showPosition / showChevrons ────────────────
  private group = inject(CorExpandablePanelsComponent);

  /** Reads showPosition directly from the parent group input. */
  showPositions = this.group.showPositions;

  /** Reads showChevrons directly from the parent group input. */
  showChevrons = this.group.showChevrons;

  // ── Controlled by parent via syncPanelStates ─────────────────────────────
  isExpanded = signal(false);
  chevronAngle = signal<number>(0);
  /** 1-based display position set by parent. */
  position = signal<number>(1);

  toggleRequested = output<void>();

  handleClick() {
    if (!this.isExpanded()) {
      this.toggleRequested.emit();
    }
  }
}

