  );
  sizeFontCard = input<TCorFontSizes>(COR_FLIP_COUNTER_DEFAULT.sizeFontCard);
  target = input.required<number>();

  // outputs
  animating$ = output<boolean>();
  value$ = output<number>();

  // styles
  protected styles = computed<string>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const colorBgBottomFlippingCard = this.colorBgBottomFlippingCard();
    const colorBgCard = this.colorBgCard();
    const colorBgTextBottomFlippingCard = this.colorBgTextBottomFlippingCard();
    const colorLeafLineCard = this.colorLeafLineCard();
    const colorTextCard = this.colorTextCard();
    const heightCard = this.heightCard();
    const roundedCard = this.roundedCard();

    const colorBgBottomFlippingCardVal = !!colorBgBottomFlippingCard
      ? cssVar(`--clr-${colorBgBottomFlippingCard}`)
      : "transparent";
    const colorBgCardVal = !!colorBgCard
      ? cssVar(`--clr-${colorBgCard}`)
