      ? cssVar(`--clr-${colorTextCard}`)
      : "transparent";
    const roundedCardVal: number = COR_ROUNDEDS?.[roundedCard];

    return `
--cor-flip-counter-clr-bg-bottom-flipping-card: ${colorBgBottomFlippingCardVal};
--cor-flip-counter-clr-bg-card: ${colorBgCardVal};
--cor-flip-counter-clr-text-bottom-flipping-card: ${colorBgTextBottomFlippingCardVal};
--cor-flip-counter-clr-leaf-line-card: ${colorLeafLineCardVal};
--cor-flip-counter-clr-text-card: ${colorTextCardVal};
--cor-flip-counter-height-card: ${heightCard}px;
--cor-flip-counter-rounded-card: ${roundedCardVal}rem;
  `
      .trim()
      .replace("\n", "");
  });

  // publics
  digits = computed(() => this.display().split(""));
  display = computed(() =>
    formataNumber(
      this.value(),
      this.minIntegerDigits(),
      this.minDecimalDigits(),
    ),
  );
  isAnimating = signal<boolean>(false);
  scrambled = signal<string>("");
  value = signal<number>(0);

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // constructor
  constructor() {
    effect((onCleanup) => {
      let start = 0;
      untracked(() => {
        start = this.value();
      });

      const target = this.target();
      const duration = this.duration();

      const cancel = this.#animateValue(
        start,
        target,
        duration,
        (val: number) => {
          // atualiza caption (scramble) com base no estado
          const useScramble = this.scrambleCaption();
          const cap = this.caption();
          this.scrambled.set(
            this.isAnimating() && useScramble ? scrambleString(cap) : cap,
          );
        },
        () => {
          this.scrambled.set(this.caption());
        },
      );

      onCleanup(() => cancel());
    });

    effect(() => this.animating$.emit(this.isAnimating()));
    effect(() => this.value$.emit(this.value()));
  }

  #animateValue(
    initial: number,
    target: number,
    duration: number,
    onUpdate: (value: number) => void,
    onComplete?: () => void,
  ): () => void {
    const startTime = performance.now();
    const delta = target - initial;
    let animationId: number | null = null;
    let cancelled = false;

    const tick = (currentTime: number) => {
      if (cancelled) return;

      this.isAnimating.set(true);

      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / duration, 1);

      const eased = 1 - Math.pow(1 - progress, 3);
      const nextValue = initial + delta * eased;

      // Se você quiser reduzir "flicker" por muitos decimais:
      // const nextValue = Math.round((initial + delta * eased) * 1000) / 1000;

      untracked(() => this.value.set(nextValue));
      onUpdate(nextValue);

      if (progress < 1) {
        animationId = requestAnimationFrame(tick);
      } else {
        this.isAnimating.set(false);
        onComplete?.();
      }
    };

    animationId = requestAnimationFrame(tick);

    return () => {
      cancelled = true;
      if (animationId !== null) cancelAnimationFrame(animationId);
      // garante estado consistente ao cancelar no meio
      this.isAnimating.set(false);
    };
  }
}

