  widthFadeRem: number;
}

@Component({
  selector: "cor-imgs-scroller",
  imports: [
    // modules
    CommonModule,
    // MatTooltipModule,
  ],
  templateUrl: "./imgs-scroller.html",
  styleUrl: "./imgs-scroller.scss",
})
export class CorImgsScrollerComponent {
  // inputs
  colorFade = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_IMGS_SCROLLER_DEFAULT.colorFade,
  );
  gap = input<TCorBsSpacings>(COR_IMGS_SCROLLER_DEFAULT.gap);
  imgs = input.required<string[]>();
  pauseOnHover = input(COR_IMGS_SCROLLER_DEFAULT.pauseOnHover, {
    transform: booleanAttribute,
  });
  reverse = input(COR_IMGS_SCROLLER_DEFAULT.reverse, {
    transform: booleanAttribute,
  });
  slideWidthPx = input<number>(COR_IMGS_SCROLLER_DEFAULT.slideWidthPx);
  speed = input<number>(COR_IMGS_SCROLLER_DEFAULT.speed); // seconds
  square = input(COR_IMGS_SCROLLER_DEFAULT.square, {
    transform: booleanAttribute,
  });
  widthFadeRem = input<number>(COR_IMGS_SCROLLER_DEFAULT.widthFadeRem);

  // publics - styles
  protected styles = computed<string>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const colorFade: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorFade();
    const slideWidthPx: number = this.slideWidthPx();
    const square: boolean = this.square();
    const gapPx: number = this.gapPx();
    const widthFadeRem: number = this.widthFadeRem();
    // console.log({ slideWidthPx, gapPx });

    // vals
    const colorFadeVal: string = !!colorFade
      ? cssVar(`--clr-${colorFade}`)
      : "transparent";

    return `
--cor-img-scroller-clr-fade: ${colorFadeVal};
--cor-img-scroller-width-slide: ${slideWidthPx}px;
--cor-img-scroller-gap: ${gapPx}px;
--cor-img-scroller-width-fade: ${widthFadeRem}rem;
--cor-img-scroller-aspect-ratio: ${square ? "1 / 1" : "16 / 9"};
  `
      .trim()
      .replace("\n", "");
  });

  // publics
  gapPx = computed<number>(() => {
    const gap: TCorBsSpacings = this.gap();
    const gapRem: number = Number(COR_BS_SPACINGS?.[gap]) || 0;
    // console.log({ gap, gapRem });
    return gapRem * 16;
  });
  offsetPx = signal(0);
  transitioning = signal(false);
  private hovered = signal(false);
  displayImages = computed(() => {
    const imgs = this.imgs();
    if (!imgs.length) return [];
    const repeats = Math.max(4, Math.ceil(120 / imgs.length));
    return Array.from({ length: repeats }, (_, i) =>
      imgs.map((src, j) => ({ src, _id: `${i}-${j}` })),
    ).flat();
  });

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );
  private stripWidth = computed(() => {
    const imgs: string[] = this.imgs() || [];
    const slideWidthPx: number = this.slideWidthPx();
    const gapPx: number = this.gapPx();
    // console.log({ l: imgs.length, slideWidthPx, gapPx, stripWidth: imgs.length * (slideWidthPx + gapPx) });

    return imgs.length * (slideWidthPx + gapPx);
  });
  private raf: number | null = null;
  private lastTs: number | null = null;

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // constructor
  constructor() {
    afterNextRender(() => {
      this.startLoop();
    });
  }

  // lifecycles
  ngOnDestroy() {
    if (this.raf !== null) cancelAnimationFrame(this.raf);
  }

  // functions
  onMouseEnter() {
    if (this.pauseOnHover()) this.hovered.set(true);
  }

  onMouseLeave() {
    this.hovered.set(false);
  }

  private startLoop() {
    const loop = (ts: number) => {
      if (this.lastTs !== null && !this.hovered()) {
        const dt = (ts - this.lastTs) / 1000;
        const dir = this.reverse() ? 1 : -1;
        const strip = this.stripWidth();

        this.offsetPx.update((v) => {
          let next = v + dir * this.speed() * dt;

          if (!this.reverse() && next <= -strip) {
            this.transitioning.set(true);
            next += strip;
            requestAnimationFrame(() => this.transitioning.set(false));
          }
          if (this.reverse() && next >= 0) {
            this.transitioning.set(true);
            next -= strip;
            requestAnimationFrame(() => this.transitioning.set(false));
          }
          return next;
        });
      }
      this.lastTs = ts;
      this.raf = requestAnimationFrame(loop);
    };

    this.raf = requestAnimationFrame(loop);
  }
}

