  );
  colorBgUfHover = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_MAPA_BRASIL_DEFAULT.colorBgUfHover);
  colorBgUfOff = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_MAPA_BRASIL_DEFAULT.colorBgUfOff,
  );
  colorBorderUf = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_MAPA_BRASIL_DEFAULT.colorBorderUf);
  colorTextUf = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_MAPA_BRASIL_DEFAULT.colorTextUf,
  );
  colorTextUfOff = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_MAPA_BRASIL_DEFAULT.colorTextUfOff);
  // dark = input(COR_MAPA_BRASIL_DEFAULT.dark, { transform: booleanAttribute });
  off = input(COR_MAPA_BRASIL_DEFAULT.off, { transform: booleanAttribute });
  uf = input<TCorUf | null>(null);
  ufs = input<Partial<Record<TCorUf, Partial<ICorMapaBrasilUfProps>>>>(
    COR_MAPA_BRASIL_DEFAULT.ufs,
  );
  widthBorderUfPx = input<number>(COR_MAPA_BRASIL_DEFAULT.widthBorderUfPx);
  zoomIn = input(COR_MAPA_BRASIL_DEFAULT.zoomIn, {
    transform: booleanAttribute,
  });

  // outputs
  select$ = output<TCorUf | null>();

  // publics - styles
  protected styles = computed<string>(() => {
    // const dark: boolean = this.dark();
    const ufsProps: Record<TCorUf, ICorMapaBrasilUfProps> = this.ufsProps();
    const colorBgUfOff:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBgUfOff();
    const colorBgUf: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorBgUf();
    const colorBorderUf:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBorderUf();
    const colorTextUfOff:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorTextUfOff();
    const widthBorderUfPx: number = this.widthBorderUfPx();

    const colorBgUfVal: string = !!colorBgUf
      ? cssVar(`--clr-${colorBgUf}`)
      : "transparent";
    const colorBgUfOffVal: string = !!colorBgUfOff
      ? cssVar(`--clr-${colorBgUfOff}`)
      : "transparent";
    const colorBorderUfVal: string = !!colorBorderUf
      ? cssVar(`--clr-${colorBorderUf}`)
      : "transparent";
    const colorTextUfOffVal: string = !!colorTextUfOff
      ? cssVar(`--clr-${colorTextUfOff}`)
      : "transparent";
    // console.log({ ufsProps });

    let hovers: string = "";
    Object.entries(ufsProps).forEach(
      ([sigla, props]) =>
        (hovers += ` --cor-mapa-brasil-clr-bg-uf-hover-${sigla}: ${props.colorBgUfHover};\n`),
    );

    return `
      ${hovers}
      --cor-mapa-brasil-clr-bg-uf: ${colorBgUfVal};
      --cor-mapa-brasil-clr-bg-uf-off: ${colorBgUfOffVal};
      --cor-mapa-brasil-clr-border-uf: ${colorBorderUfVal};
      --cor-mapa-brasil-clr-text-uf-off: ${colorTextUfOffVal};
      --cor-mapa-brasil-width-border-uf: ${widthBorderUfPx}px;
      `
      .trim()
      .replace("\n", "");
  });

  // publics - ufs
  ufsProps = computed<Record<TCorUf, ICorMapaBrasilUfProps>>(() => {
    const ufs = this.ufs() || {};
    // const dark: boolean = this.dark();
    const off: boolean = !!this.off();
    const colorBgUf: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorBgUf();
    const colorBgUfHover:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBgUfHover();
    const colorTextUf: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorTextUf();

    const colorBgDefVal: string = !!colorBgUf
      ? cssVar(`--clr-${colorBgUf}`)
      : "transparent";
    const colorBgDefHoverVal: string = !!colorBgUfHover
      ? cssVar(`--clr-${colorBgUfHover}`)
      : "transparent";
    const colorTextDefVal: string = !!colorTextUf
      ? cssVar(`--clr-${colorTextUf}`)
      : "transparent";

    const ufsProps: Record<TCorUf, ICorMapaBrasilUfProps> =
      COR_SIGLAS_UFS.reduce(
        (acc, uf) => {
          const colorBgUfVal: string = !!ufs[uf]?.colorBgUf
            ? cssVar(`--clr-${ufs[uf]?.colorBgUf}`)
            : "";
          const colorBgUfHoverVal: string = !!ufs[uf]?.colorBgUfHover
            ? cssVar(`--clr-${ufs[uf]?.colorBgUfHover}`)
            : "";
          const colorTextUfVal: string = !!ufs[uf]?.colorTextUf
            ? cssVar(`--clr-${ufs[uf]?.colorTextUf}`)
            : "";

          acc[uf] = {
            off: ufs[uf]?.off || off,
            colorBgUf: colorBgUfVal || colorBgDefVal,
            colorBgUfHover: colorBgUfHoverVal || colorBgDefHoverVal,
            colorTextUf: colorTextUfVal || colorTextDefVal,
          };
          return acc;
        },
        {} as Record<TCorUf, ICorMapaBrasilUfProps>,
      );
    // console.log({ ufsProps });

    return ufsProps;
  });

  // publics
  // selected = signal<string | null>(null);
  svgViewBox = computed(() => {
    const v = this.viewBoxSignal();
    return `${v.x} ${v.y} ${v.w} ${v.h}`;
  });

  // privates
  /** Animated viewBox */
  /** Original SVG viewBox (full map) */
  #baseViewBox = {
    x: 0,
    y: 0,
    w: 460,
    h: 460,
  };
  private viewBoxSignal = signal(this.#baseViewBox);
  #animationFrameId: number | null = null;
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // constructor
  constructor() {
    inject(DestroyRef).onDestroy(() => {
      if (this.#animationFrameId !== null) {
        cancelAnimationFrame(this.#animationFrameId);
      }
    });

    effect(() => {
      const zoomIn = this.zoomIn(); // rastreado
      const uf = this.uf(); // rastreado

      // Se zoomIn estiver DESLIGADO: nunca faz zoom por UF, nunca anima por UF
      if (!zoomIn) {
        // cancela animação e garante mapa inteiro
        if (this.#animationFrameId !== null) {
          cancelAnimationFrame(this.#animationFrameId);
          this.#animationFrameId = null;
        }
        this.viewBoxSignal.set(this.#baseViewBox);
        return;
      }

      // Se zoomIn estiver LIGADO: aplica zoom/centralização por UF (com animação)
      untracked(() => {
        if (!uf) {
          this.#animateViewBox(this.#baseViewBox);
          return;
        }

        const path = this.svgRef.nativeElement.querySelector(
          `a.${uf} path`,
        ) as SVGGraphicsElement | null;

        if (!path) return;

        const box = path.getBBox();
        const padding = 20;

        this.#animateViewBox({
          x: box.x - padding,
          y: box.y - padding,
          w: box.width + padding * 2,
          h: box.height + padding * 2,
        });
      });
    });
  }

  // functions
  #animateViewBox(target: { x: number; y: number; w: number; h: number }) {
    // Cancela qualquer animação em andamento
    if (this.#animationFrameId !== null) {
      cancelAnimationFrame(this.#animationFrameId);
      this.#animationFrameId = null;
    }

    const start = { ...this.viewBoxSignal() }; // snapshot imutável do estado atual
    const duration = 300;
    const startTime = performance.now();

    const easeOut = (t: number) => 1 - Math.pow(1 - t, 3);

    const frame = (now: number) => {
      const progress = Math.min((now - startTime) / duration, 1);
      const e = easeOut(progress);

      this.viewBoxSignal.set({
        x: start.x + (target.x - start.x) * e,
        y: start.y + (target.y - start.y) * e,
        w: start.w + (target.w - start.w) * e,
        h: start.h + (target.h - start.h) * e,
      });

      if (progress < 1) {
        this.#animationFrameId = requestAnimationFrame(frame);
      } else {
        this.#animationFrameId = null;
      }
    };

    this.#animationFrameId = requestAnimationFrame(frame);
  }

  // methods
  onUfClick(uf: TCorUf | null) {
    this.select$.emit(this.uf() === uf ? null : uf);
  }
}

