    const colorDropdownBgActive:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | ""
      | TCorThemesIds
      | "" = this.colorDropdownBgActive();
    const colorDropdownBorder:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | ""
      | TCorThemesIds
      | "" = this.colorDropdownBorder();
    const colorDropdownText:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | ""
      | TCorThemesIds
      | "" = this.colorDropdownText();
    const colorDropdownTextActive:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | ""
      | TCorThemesIds
      | "" = this.colorDropdownTextActive();
    const colorNavBgActive:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | ""
      | TCorThemesIds
      | "" = this.colorNavBgActive();
    const colorNavBorderActive:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | ""
      | TCorThemesIds
      | "" = this.colorNavBorderActive();
    const colorNavText:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | ""
      | TCorThemesIds
      | "" = this.colorNavText();
    const colorNavTextActive:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | ""
      | TCorThemesIds
      | "" = this.colorNavTextActive();
    const roundedDropdown: TCorRoundeds = this.roundedDropdown();
    const sizeNavBorderActive: TCorBorderSizes = this.sizeNavBorderActive();
    const sizeDropdownBorder: TCorBorderSizes = this.sizeDropdownBorder();

    const widthMin: number = this.widthMin();
    // const colorDropdownBgVal: string = 'rgba(0,0,0,.9)';
    const colorDropdownBgVal: string = !!colorDropdownBg
      ? hslStrToRgba(cssVar(`--clr-${colorDropdownBg}`), 0.9)
      : "transparent";
    // const colorDropdownBgVal: string = !!colorDropdownBg ? cssVar(`--clr-${colorDropdownBg}`) : 'transparent';
    const colorDropdownBgActiveVal: string = !!colorDropdownBgActive
      ? cssVar(`--clr-${colorDropdownBgActive}`)
      : "transparent";
    const colorDropdownBorderVal: string = !!colorDropdownBorder
      ? cssVar(`--clr-${colorDropdownBorder}`)
      : "transparent";
    const colorDropdownTextVal: string = !!colorDropdownText
      ? cssVar(`--clr-${colorDropdownText}`)
      : "transparent";
    const colorDropdownTextActiveVal: string = !!colorDropdownTextActive
      ? cssVar(`--clr-${colorDropdownTextActive}`)
      : "transparent";
    const colorNavBgActiveVal: string = !!colorNavBgActive
      ? cssVar(`--clr-${colorNavBgActive}`)
      : "transparent";
    const colorNavBorderActiveVal: string = !!colorNavBorderActive
      ? cssVar(`--clr-${colorNavBorderActive}`)
      : "transparent";
    const colorNavTextVal: string = !!colorNavText
      ? cssVar(`--clr-${colorNavText}`)
      : "transparent";
    const colorNavTextActiveVal: string = !!colorNavTextActive
      ? cssVar(`--clr-${colorNavTextActive}`)
      : "transparent";
    const roundedDropdownVal: number = COR_ROUNDEDS?.[roundedDropdown];
    const sizeNavBorderActiveVal: number =
      COR_BORDER_SIZES?.[sizeNavBorderActive];
    const sizeDropdownBorderVal: number =
      COR_BORDER_SIZES?.[sizeDropdownBorder];
    // console.log({ colorNavBgActive, colorNavBgActiveVal });

    return `
      --cor-nav-clr-dropdown-bg: ${colorDropdownBgVal};
      --cor-nav-clr-dropdown-bg-active: ${colorDropdownBgActiveVal};
      --cor-nav-clr-dropdown-border: ${colorDropdownBorderVal};
      --cor-nav-clr-dropdown-text: ${colorDropdownTextVal};
      --cor-nav-clr-dropdown-text-active: ${colorDropdownTextActiveVal};
      --cor-nav-clr-nav-bg-active: ${colorNavBgActiveVal};
      --cor-nav-clr-nav-border-active: ${colorNavBorderActiveVal};
      --cor-nav-clr-nav-text: ${colorNavTextVal};
      --cor-nav-clr-nav-text-active: ${colorNavTextActiveVal};
      --cor-nav-rounded-dropdown: ${roundedDropdownVal}rem;
      --cor-nav-size-nav-border-active: ${sizeNavBorderActiveVal}px;
      --cor-nav-size-dropdown-border: ${sizeDropdownBorderVal}px;
      --cor-nav-width-min: ${widthMin}px;
`
      .trim()
      .replace("\n", "");
  });

  // publics
  private itemCloseTimer: ReturnType<typeof setTimeout> | null = null;
  private subCloseTimer: ReturnType<typeof setTimeout> | null = null;
  tabs = contentChildren(CorNavComponent);
  openNavIndex = signal<number>(-1);
  openNavId = signal<string | null>(null);
  openDropdownId = signal<string | null>(null);
  openSubId = signal<string | null>(null);
  // isNavHovered = signal<boolean>(false);
  indicator = signal({
    left: 0,
    width: 0,
    height: 0,
    top: 0,
  });
  data = computed(() =>
    this.items().map((n: ICorNavItem) => ({
      ...n,
      __hasIcons: this.items()?.some((i1: ICorNavItem) => !!i1?.icon),
      __hasTarget: !!n?.url /* || !!n?.onClick */,
      children: (n?.children || []).map((i2: ICorNavItem) => ({
        ...i2,
        __hasIcons: n?.children?.some((i1: ICorNavItem) => !!i1?.icon),
        __hasTarget: !!i2?.url /* || !!i2?.onClick */,
        children: (i2?.children || []).map((i3: ICorNavItem) => ({
          ...i3,
          __hasIcons: i2?.children?.some((i2: ICorNavItem) => !!i2?.icon),
          __hasTarget: !!i3?.url /* || !!i3?.onClick */,
        })),
      })),
    })),
  );

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);
  #injector = inject(Injector);
  #router = inject(Router);

  // constructor
  constructor() {
    afterNextRender(
      () => {
        this.#updateIndicator(0);
      },
      { injector: this.#injector },
    );

    effect(() => {
      const index: number = this.openNavIndex();
      // console.log({ index });
      /* index > 0 && */ this.#updateIndicator(index);
    });

    // Effect: reset sub-menu whenever the top-level item changes
    effect(() => {
      this.openNavId(); // track signal
      // this.#clearSubTimer();
      this.openDropdownId.set(null);
    });
  }

  // lifecycle
  // ngAfterViewInit() {
  //   console.log(this.tabsRef);
  // }

  ngOnDestroy(): void {
    // this.#clearItemTimer();
    // this.#clearSubTimer();
  }

  // functions
  #updateIndicator(index: number) {
    // const openNavIndex: number = this.openNavIndex();
    const el = this.tabsRef?.get(index)?.nativeElement;
    // console.log({ el });
    if (!el) {
      return;
    }

    const { offsetLeft, offsetTop, clientWidth, clientHeight } = el;
    // console.log({ offsetLeft, offsetTop, clientWidth, clientHeight });

    this.indicator.set({
      left: offsetLeft,
      top: offsetTop,
      width: clientWidth,
      height: clientHeight,
    });
  }

  // #clearItemTimer(): void {
  //   if (this.itemCloseTimer !== null) {
  //     clearTimeout(this.itemCloseTimer);
  //     this.itemCloseTimer = null;
  //   }
  // }

  // #clearSubTimer(): void {
  //   if (this.subCloseTimer !== null) {
  //     clearTimeout(this.subCloseTimer);
  //     this.subCloseTimer = null;
  //   }
  // }

  onItemClick(i: ICorNavItem, e: Event) {
    // console.log({ i, e });
    if (!!i?.url) {
      this.#router.navigateByUrl(i?.url);
      this.openNavId.set(null);
      this.openDropdownId.set(null);
    } else {
      // !!i?.onClick && i?.onClick();
    } // if
  }

  onNavHover(index: number, item?: ICorNavItem): void {
    this.openNavIndex() !== index && this.openNavIndex.set(index);
    if (index < 0) {
      this.openNavId.set(null);
      // this.itemCloseTimer = setTimeout(() => this.openNavId.set(null), CLOSE_DELAY);
      this.openNavId.set(null);
    } else {
      // this.#clearItemTimer();
      this.openNavId.set(item?.id ?? null);
    }
  }

  onDropdownEnter(id?: string): void {
    if (!id) {
      // this.subCloseTimer = setTimeout(() => this.openDropdownId.set(null), CLOSE_DELAY);
      this.openDropdownId.set(null);
    } else {
      // this.#clearSubTimer();
      this.openDropdownId.set(id);
    } // else
  }
}

export interface ICorPagination {
  page: number;
  itemsPerPage: number;
  totalItems: number;
}

export interface ICorPaginationChange extends ICorPagination {
  totalPages: number;
  rangeStart?: number;
  rangeEnd?: number;
}

export interface ICorPaginationData<T> extends ICorPaginationChange {
  data: T[];
}

export interface ICorPaginationProps {
  alwaysVisible: boolean;
  bold: TCorFontWeights;
  boldActive: TCorFontWeights;
  changeSize: boolean;
  colorBtnBg: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBtnBgHover: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBtnBorderHover: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBtnBgActive: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBtnBorderActive: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBtnBorder: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBtnText: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBtnTextActive: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  colorBtnTextHover: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "";
  gap: TCorBsSpacings;
  isMobile: boolean;
  off: boolean;
  rounded: TCorRoundeds;
  paddingX: Exclude<TCorSpacings, "auto">;
  paddingY: Exclude<TCorSpacings, "auto">;
  sizeBorder: TCorBorderSizes;
  sizeCaption: string;
  sizeFont: TCorFontSizes;
  sizeFontActive: TCorFontSizes;
}

@Component({
