  >(COR_PAGINATION_DEFAULT?.colorBtnBgHover);
  colorBtnBorder = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_PAGINATION_DEFAULT?.colorBtnBorder);
  colorBtnBorderActive = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_PAGINATION_DEFAULT?.colorBtnBorderActive);
  colorBtnBorderHover = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_PAGINATION_DEFAULT?.colorBtnBorderHover);
  colorBtnText = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_PAGINATION_DEFAULT?.colorBtnText,
  );
  colorBtnTextActive = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_PAGINATION_DEFAULT?.colorBtnTextActive);
  colorBtnTextHover = input<
    TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | ""
  >(COR_PAGINATION_DEFAULT?.colorBtnTextHover);
  changeSize = input(COR_PAGINATION_DEFAULT.changeSize, {
    transform: booleanAttribute,
  });
  gap = input<TCorBsSpacings>(COR_PAGINATION_DEFAULT.gap);
  isMobile = input(COR_PAGINATION_DEFAULT.isMobile, {
    transform: booleanAttribute,
  });
  off = input(COR_PAGINATION_DEFAULT.off, { transform: booleanAttribute });
  paddingX = input<Exclude<TCorSpacings, "auto">>(
