  // outputs
  change$ = output<ICorPaginationChange>();
  pagChange$ = output<number>();
  itemsPerPageChange$ = output<number>();

  // publics - styles
  protected styles = computed<string>(() => {
    const isDarkMode: boolean = this.isDarkMode();
    const bold: TCorFontWeights = this.bold();
    const boldActive: TCorFontWeights = this.boldActive();
    const colorBtnBg: TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "" =
      this.colorBtnBg();
    const colorBtnBgActive:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBtnBgActive();
    const colorBtnBgHover:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBtnBgHover();
    const colorBtnBorderActive:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBtnBorderActive();
    const colorBtnBorder:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBtnBorder();
    const colorBtnBorderHover:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBtnBorderHover();
    const colorBtnTextActive:
      | TCorBaseColorIds
      | TCorCtaColorIds
      | TCorThemesIds
      | "" = this.colorBtnTextActive();
    const colorBtnTextHover:
