    const paddingX: Exclude<TCorSpacings, "auto"> = this.paddingX();
    const paddingY: Exclude<TCorSpacings, "auto"> = this.paddingY();
    const sizeBorder: TCorBorderSizes = this.sizeBorder();
    const sizeFont: TCorFontSizes = this.sizeFont();
    const sizeFontActive: TCorFontSizes = this.sizeFontActive();
    const rounded: TCorRoundeds = this.rounded();

    const boldVal: number = COR_FONT_WEIGHTS?.[bold];
    const boldActiveVal: number = COR_FONT_WEIGHTS?.[boldActive];
    const colorBtnBgVal: string = !!colorBtnBg
