export class CorSidenavComponent {
  // ── inputs ──────────────────────────────────────────────────────────────────

  /** Alternativa ao config objeto: aceita um subconjunto de ICorSidenavProps */
  config = input<Partial<ICorSidenavProps> | null>(null);

