  });
  // private host = inject(ElementRef<HTMLElement>);
  tabs = contentChildren(CorTabComponent);
  hoverIndex = signal<number | null>(null);
  // indicatorLeft = signal(0);
  // indicatorWidth = signal(0);

  // privates
  private readonly isDarkMode = computed<boolean>(() =>
    this.#corThemeServ.isDarkMode(),
  );

  // injects
  #corThemeServ: CorThemeService = inject(CorThemeService);

  // constructor
  constructor() {
    effect(() => {
      const hoverIndex: number | null = this.hoverIndex();
      this.hoveredIndex$.emit(hoverIndex);
    });

    // Sync tab logic
    effect(() => {
      const activeIndex: number = this.activeIndex();
      const tabs = this.tabs() || [];

      tabs.forEach((tab: CorTabComponent, i: number) => {
        tab.active.set(i === activeIndex);
        tab.activate = () => this.activeIndex$.emit(i); // this.activeIndex.set(i);
        tab.hover = () => this.hoverIndex.set(i);
        tab.leave = () => this.hoverIndex.set(null);
      });
    });

    // Update indicator when hover/active changes
    effect(() => {
      const index = this.hoverIndex() ?? this.activeIndex();
      queueMicrotask(() => this.updateIndicator(index));
    });

    // Resize observer
    // effect(
    //   () => {
    //     const resizeObserver = new ResizeObserver(
    //       () => {
    //         const index = this.hoverIndex() ?? this.activeIndex();
    //         this.updateIndicator(index);
    //       }
    //     );

    //     resizeObserver.observe(this.host.nativeElement);
    //     return () => resizeObserver.disconnect();
    //   }
    // );
  }

  // functions
  private updateIndicator(index: number) {
    const tabs = this.tabs();
    const tab = tabs[index];
    // console.log(tab.off());
    if (!tab) return;

    const el = tab.el.nativeElement;

    // this.indicatorLeft.set(el.offsetLeft);
    // this.indicatorWidth.set(el.offsetWidth);
    // const borderSize: number = COR_BORDER_SIZES?.[this.sizeBorder()];
    const { offsetLeft, offsetTop, clientWidth, clientHeight } = el;
    // console.log({ offsetLeft, offsetTop, clientWidth, clientHeight });
    // console.log(this.sizeBorder(), { borderSize });

    !tab.off() &&
      this.indicator.set({
        left: offsetLeft /*  + borderSize */,
        top: offsetTop /*  + borderSize */,
        width: clientWidth,
        height: clientHeight,
      });
  }
}

