// 'I build with Angular signals.\nI type letter by letter.\nI loop through multiple strings.\nI am a typewriter.'

@Component({
  selector: "cor-typewriter",
  imports: [
    // modules
    CommonModule,
  ],
  templateUrl: "./typewriter.html",
  styleUrl: "./typewriter.scss",
})
export class CorTypewriterComponent {
  // inputs
  bold = input<TCorFontWeights>(COR_TYPEWRITER_DEFAULT.bold);
  colorText = input<TCorBaseColorIds | TCorCtaColorIds | TCorThemesIds | "">(
    COR_TYPEWRITER_DEFAULT.colorText,
  );
  delay = input<number>(COR_TYPEWRITER_DEFAULT.delay); // Initial delay in ms before the first character is typed.
  eraseSpeed = input<number>(COR_TYPEWRITER_DEFAULT.eraseSpeed); // Characters erased per second (used when transition = 'erase').
  loop = input(COR_TYPEWRITER_DEFAULT.loop, { transform: booleanAttribute }); // Loop through the array indefinitely.
  pauseAfterErase = input<number>(COR_TYPEWRITER_DEFAULT.pauseAfterErase); // Pause in ms after erasing / clearing, before typing the next string.
  pauseAfterType = input<number>(COR_TYPEWRITER_DEFAULT.pauseAfterType); // Pause in ms after fully typing a string, before erasing / moving on.
  sizeFont = input<TCorFontSizes>(COR_TYPEWRITER_DEFAULT.sizeFont);
  speed = input<number>(COR_TYPEWRITER_DEFAULT.speed);
  texts = input.required<string[]>();
  tracking = input<TCorLetterSpacings>(COR_TYPEWRITER_DEFAULT.tracking);
  transition = input<TCorTypewriterTransitions>(
    COR_TYPEWRITER_DEFAULT.transition,
  );

  // publics
  displayed = signal("");
  isIdle = signal(false);

  // privates
  #accumulated = "";
  #charIndex = 0;
  #stringIndex = 0;
  #timerId: ReturnType<typeof setTimeout> | null = null;

  // constructor
  constructor() {
    effect(() => {
      // Read all inputs so the effect re-runs when any changes
      const texts: string[] = this.texts();
      const delay: number = this.delay();
      void this.speed();
      void this.eraseSpeed();
      void this.pauseAfterType();
      void this.pauseAfterErase();
      void this.transition();
      void this.loop();

      this.#hardReset();
      this.#timerId = setTimeout(() => this.#typeNext(), delay);
    });
  }

  // lifecycles
  ngOnDestroy(): void {
    this.#hardReset();
  }

  // functions
  private get strings(): string[] {
    const t = this.texts();
    return Array.isArray(t) ? t : [t];
  }

  #currentString(): string {
    return this.strings[this.#stringIndex] ?? "";
  }

  #hardReset(): void {
    if (this.#timerId !== null) {
      clearTimeout(this.#timerId);
      this.#timerId = null;
    }
    this.#stringIndex = 0;
    this.#charIndex = 0;
    this.#accumulated = "";
    this.displayed.set("");
    this.isIdle.set(false);
  }

  #schedule(fn: () => void, ms: number): void {
    this.#timerId = setTimeout(fn, ms);
  }

  // functions: Type / Erase machine
  #typeNext(): void {
    this.#charIndex = 0;
    this.isIdle.set(false);
    this.#typeTick();
  }

  #typeTick(): void {
    const str = this.#currentString();
    const interval = 1000 / Math.max(this.speed(), 1);

    if (this.#charIndex <= str.length) {
      this.displayed.set(this.#accumulated + str.slice(0, this.#charIndex++));
      this.#schedule(() => this.#typeTick(), interval);
    } else {
      this.#onTypingDone();
    }
  }

  #onTypingDone(): void {
    const strings = this.strings;
    const isLast = this.#stringIndex === strings.length - 1;

    if (strings.length === 1 || (isLast && !this.loop())) {
      this.isIdle.set(true); // nothing more to do
      return;
    }

    this.isIdle.set(true);
    this.#schedule(() => this.#beginTransition(), this.pauseAfterType());
  }

  #beginTransition(): void {
    switch (this.transition()) {
      case "erase":
        this.#eraseTick();
        break;

      case "clear":
        this.displayed.set(this.#accumulated);
        this.#advanceString();
        this.#schedule(() => this.#typeNext(), this.pauseAfterErase());
        break;

      case "replace":
        this.#advanceString();
        this.#typeNext();
        break;

      case "append":
        this.#accumulated = this.displayed() + "\n";
        this.#advanceString();
        this.#schedule(() => this.#typeNext(), this.pauseAfterErase());
        break;
    }
  }

  #eraseTick(): void {
    const interval = 1000 / Math.max(this.eraseSpeed(), 1);
    const visible = this.displayed().slice(this.#accumulated.length);

    if (visible.length > 0) {
      this.displayed.set(this.#accumulated + visible.slice(0, -1));
      this.#schedule(() => this.#eraseTick(), interval);
    } else {
      this.#advanceString();
      this.#schedule(() => this.#typeNext(), this.pauseAfterErase());
    }
  }

  #advanceString(): void {
    this.#stringIndex = (this.#stringIndex + 1) % this.strings.length;
  }
}

export const onDestroy = (): Subject<void> => {
  const destroyAction$ = new Subject<void>();
  const viewRef = inject(ChangeDetectorRef) as ViewRef;

  viewRef?.onDestroy(() => {
    destroyAction$?.next();
    destroyAction$?.complete();
  });

  return destroyAction$;
};

export interface IMockResourceResponse {
  error(): Error | null;
  value(): any;
  status(): TResourceStatus | null;
  reload(): void;
}

export function mockResource<T>(
  data?: T,
  error?: Error,
  isLoading?: boolean,
): IMockResourceResponse {
  // console.log({ data, error });
  const isLoadingStatus: boolean | null = isLoading ?? null;
  const err: Error | null =
    isLoadingStatus === true ? null : !!error ? error : null;
  const val: T | null =
    isLoadingStatus === true ? null : !err ? data || null : null;
  const stat: TResourceStatus =
    isLoadingStatus === true
      ? "loading"
      : !!error
        ? "error"
        : !!val
          ? "resolved"
          : "idle";
  // console.log({ err, val, stat });
  return {
    error: (): Error | null => err,
    value: (): T | null => val,
    status: (): TResourceStatus => stat,
    reload: () => console.log("Mocked reload."),
  };
}

export function printDialog(html: string): void {
  const IFRAME = document.createElement("iframe");
  IFRAME.setAttribute("style", "display: none");
  IFRAME.setAttribute("srcdoc", html);
  document.body.appendChild(IFRAME);
  setTimeout(() => {
    IFRAME?.contentWindow?.print();
  }, 1000);
}

export const dimensions = (): { w: number; h: number } => {
  let w: number;
  let h: number;
  if (window.innerWidth !== undefined && window.innerHeight !== undefined) {
    w = window.innerWidth;
    h = window.innerHeight;
  } else {
    w = document.documentElement.clientWidth;
    h = document.documentElement.clientHeight;
  } // else

  return { w, h };
};

export const copyToClipboard = (text: string) => {
  var dummy = document.createElement("textarea");
  // to avoid breaking orgain page when copying more words
  // cant copy when adding below this code
  // dummy.style.display = 'none'
  document.body.appendChild(dummy);
  //Be careful if you use texarea. setAttribute('value', value), which works with "input" does not work with "textarea". – Eduard
  dummy.value = text;
  dummy.select();
  document.execCommand("copy");
  document.body.removeChild(dummy);
};

export const isUrl = (urlString: string): boolean => {
  const INPUT_ELEMENT = document.createElement("input");
  INPUT_ELEMENT.type = "url";
  INPUT_ELEMENT.value = urlString;
  return INPUT_ELEMENT.checkValidity();
};
